import React, { useEffect, useRef, forwardRef, useImperativeHandle } from 'react';
import * as d3 from 'd3';
import { ElementType, LayoutElement } from '../types';
import { useStore } from '../store';

const ELEMENT_STYLES: Record<string, { fill: string; opacity: number; stroke?: string; strokeWidth?: number }> = {
  // Structure
  [ElementType.SLAB]: { fill: '#0f172a', opacity: 1 },
  [ElementType.WALL_EXTERNAL]: { fill: '#f1f5f9', opacity: 1 },
  [ElementType.WALL_INTERNAL]: { fill: '#94a3b8', opacity: 1 },
  [ElementType.SHEAR_WALL]: { fill: '#cbd5e1', opacity: 1 },
  [ElementType.PILLAR]: { fill: '#f1f5f9', opacity: 1 },

  // Circulation
  [ElementType.CORRIDOR]: { fill: '#1e293b', opacity: 0.6, stroke: '#334155', strokeWidth: 1 },
  [ElementType.LOBBY]: { fill: '#1e293b', opacity: 0.8, stroke: '#334155', strokeWidth: 1 },
  [ElementType.AISLE]: { fill: '#1e293b', opacity: 0.5 },

  // Core
  [ElementType.ELEVATOR_SHAFT]: { fill: '#334155', opacity: 1 },
  [ElementType.STAIRCASE]: { fill: '#334155', opacity: 1 },
  [ElementType.SERVICE_SHAFT]: { fill: '#0f172a', opacity: 1, stroke: '#475569', strokeWidth: 1 },
  [ElementType.ELEVATOR_HALL]: { fill: '#1e293b', opacity: 0.9 },

  // Zones
  [ElementType.LIVING_ZONE]: { fill: '#3b82f6', opacity: 0.15, stroke: '#3b82f6', strokeWidth: 0.5 },
  [ElementType.BEDROOM_ZONE]: { fill: '#8b5cf6', opacity: 0.15, stroke: '#8b5cf6', strokeWidth: 0.5 },
  [ElementType.KITCHEN_ZONE]: { fill: '#f59e0b', opacity: 0.15, stroke: '#f59e0b', strokeWidth: 0.5 },
  [ElementType.BATHROOM_ZONE]: { fill: '#10b981', opacity: 0.15, stroke: '#10b981', strokeWidth: 0.5 },
  [ElementType.STORAGE_ZONE]: { fill: '#64748b', opacity: 0.15, stroke: '#64748b', strokeWidth: 0.5 },

  // Openings
  [ElementType.DOOR]: { fill: '#f1f5f9', opacity: 1 },
  [ElementType.FIRE_DOOR]: { fill: '#ef4444', opacity: 1 },
  [ElementType.WINDOW]: { fill: '#38bdf8', opacity: 0.4, stroke: '#38bdf8', strokeWidth: 2 },

  // MEP & Safety
  [ElementType.FIRE_HYDRANT]: { fill: '#ef4444', opacity: 1 },
  [ElementType.SAFE_EXIT_SIGN]: { fill: '#22c55e', opacity: 1 },
  [ElementType.HVAC_VENT]: { fill: '#94a3b8', opacity: 0.5 },
  [ElementType.ELECTRICAL_BOX]: { fill: '#eab308', opacity: 1 }
};

export interface MapRendererHandle {
  downloadJpg: () => void;
}

const MapRenderer = forwardRef<MapRendererHandle>((props, ref) => {
  const svgRef = useRef<SVGSVGElement>(null);
  const { layout, violations } = useStore();

  useImperativeHandle(ref, () => ({
    downloadJpg: () => {
      if (!svgRef.current || !layout) return;
      const svgNode = svgRef.current;
      const zoomGroup = d3.select(svgNode).select("g.main-group");
      const prevTransform = zoomGroup.attr("transform");
      zoomGroup.attr("transform", null); 
      svgNode.setAttribute("width", layout.width.toString());
      svgNode.setAttribute("height", layout.height.toString());
      svgNode.setAttribute("viewBox", `0 0 ${layout.width} ${layout.height}`);

      const serializer = new XMLSerializer();
      let svgString = serializer.serializeToString(svgNode);
      if (!svgString.match(/^<svg[^>]+xmlns="http\:\/\/www\.w3\.org\/2000\/svg"/)) {
        svgString = svgString.replace(/^<svg/, '<svg xmlns="http://www.w3.org/2000/svg"');
      }

      if (prevTransform) zoomGroup.attr("transform", prevTransform);

      const img = new Image();
      img.onload = () => {
        const canvas = document.createElement("canvas");
        canvas.width = layout.width;
        canvas.height = layout.height;
        const ctx = canvas.getContext("2d");
        if (ctx) {
          ctx.imageSmoothingEnabled = false; 
          ctx.fillStyle = "#0f172a"; 
          ctx.fillRect(0, 0, canvas.width, canvas.height);
          ctx.drawImage(img, 0, 0);
          const jpgUrl = canvas.toDataURL("image/jpeg", 0.98);
          const link = document.createElement("a");
          link.download = `floor_plan_${Date.now()}.jpg`;
          link.href = jpgUrl;
          document.body.appendChild(link);
          link.click();
          document.body.removeChild(link);
        }
      };
      img.src = "data:image/svg+xml;base64," + btoa(unescape(encodeURIComponent(svgString)));
    }
  }));

  useEffect(() => {
    if (!layout || !svgRef.current) return;
    const svg = d3.select(svgRef.current);
    svg.selectAll("*").remove(); 

    const { width, height, elements } = layout;
    svg.attr("viewBox", `0 0 ${width} ${height}`)
       .attr("width", "100%")
       .attr("height", "100%")
       .style("shape-rendering", "geometricPrecision"); 

    const mainGroup = svg.append("g").attr("class", "main-group");

    // Updated Architectural Z-Order
    const zOrder = [
        ElementType.SLAB,
        ElementType.LIVING_ZONE,
        ElementType.BEDROOM_ZONE,
        ElementType.KITCHEN_ZONE,
        ElementType.BATHROOM_ZONE,
        ElementType.STORAGE_ZONE,
        ElementType.CORRIDOR,
        ElementType.LOBBY,
        ElementType.AISLE,
        ElementType.ELEVATOR_HALL,
        ElementType.SERVICE_SHAFT,
        ElementType.STAIRCASE,
        ElementType.ELEVATOR_SHAFT,
        ElementType.WALL_INTERNAL,
        ElementType.SHEAR_WALL,
        ElementType.WALL_EXTERNAL,
        ElementType.PILLAR,
        ElementType.WINDOW,
        ElementType.DOOR,
        ElementType.FIRE_DOOR,
        ElementType.FIRE_HYDRANT,
        ElementType.SAFE_EXIT_SIGN,
        ElementType.ELECTRICAL_BOX
    ];

    const sortedElements = [...elements].sort((a, b) => {
      const idxA = zOrder.indexOf(a.type as ElementType);
      const idxB = zOrder.indexOf(b.type as ElementType);
      return (idxA === -1 ? 999 : idxA) - (idxB === -1 ? 999 : idxB);
    });

    mainGroup.selectAll("g.element")
      .data(sortedElements)
      .enter()
      .append("g")
      .attr("class", "element")
      .attr("transform", d => {
          const rotation = d.rotation || 0;
          return `translate(${d.x}, ${d.y}) rotate(${rotation}, ${d.width/2}, ${d.height/2})`;
      })
      .each(function(this: any, d) {
        const g = d3.select(this);
        const style = ELEMENT_STYLES[d.type as string] || { fill: '#ff00ff', opacity: 0.5 };
        const w = d.width;
        const h = d.height;
        const cx = w / 2;
        const cy = h / 2;

        if (d.type === ElementType.WINDOW) {
            // Render Window as glass pane
            g.append("rect")
             .attr("width", w)
             .attr("height", h)
             .attr("fill", style.fill)
             .attr("opacity", style.opacity)
             .attr("stroke", style.stroke || 'none')
             .attr("stroke-width", style.strokeWidth || 0);

            // Middle pane line
            const isHorizontal = w > h;
            g.append("line")
             .attr("x1", isHorizontal ? 0 : cx).attr("y1", isHorizontal ? cy : 0)
             .attr("x2", isHorizontal ? w : cx).attr("y2", isHorizontal ? h : cy)
             .attr("stroke", "#fff").attr("stroke-width", 0.5).attr("opacity", 0.8);
        } 
        else if (d.type === ElementType.STAIRCASE) {
            // Render Stairs with steps
            g.append("rect").attr("width", w).attr("height", h).attr("fill", style.fill).attr("opacity", 1);
            const isHorizontal = w > h;
            const stepSize = 8;
            const stepCount = Math.floor((isHorizontal ? w : h) / stepSize);

            for(let i=1; i<stepCount; i++) {
                g.append("line")
                 .attr("x1", isHorizontal ? i * stepSize : 0).attr("y1", isHorizontal ? 0 : i * stepSize)
                 .attr("x2", isHorizontal ? i * stepSize : w).attr("y2", isHorizontal ? h : i * stepSize)
                 .attr("stroke", "#0f172a").attr("stroke-width", 1);
            }

            // Direction Arrow
            const arrowSize = Math.min(w, h) * 0.3;
            g.append("path")
             .attr("d", isHorizontal ? `M 10 ${cy} L ${w-10} ${cy} M ${w-20} ${cy-5} L ${w-10} ${cy} L ${w-20} ${cy+5}` : `M ${cx} 10 L ${cx} ${h-10} M ${cx-5} ${h-20} L ${cx} ${h-10} L ${cx+5} ${h-20}`)
             .attr("stroke", "#f1f5f9").attr("fill", "none").attr("stroke-width", 1.5);
        }
        else if (d.type === ElementType.DOOR || d.type === ElementType.FIRE_DOOR) {
            // Render Door swing arc
            const rotation = d.rotation || 0;
            const isFire = d.type === ElementType.FIRE_DOOR;

            g.append("rect")
             .attr("width", w)
             .attr("height", h)
             .attr("fill", isFire ? '#ef4444' : '#f1f5f9')
             .attr("rx", 1);

            // Simple swing arc visualization
            const arcRadius = Math.max(w, h);
            g.append("path")
             .attr("d", `M 0 0 A ${arcRadius} ${arcRadius} 0 0 1 ${arcRadius} ${arcRadius}`)
             .attr("fill", "none")
             .attr("stroke", style.fill)
             .attr("stroke-dasharray", "2,2")
             .attr("opacity", 0.5)
             .attr("transform", `translate(0, 0) scale(${w/arcRadius}, ${h/arcRadius})`);
        }
        else if (d.type === ElementType.PILLAR) {
            g.append("rect")
             .attr("width", w).attr("height", h)
             .attr("fill", style.fill)
             .attr("stroke", "#0f172a")
             .attr("stroke-width", 1);
        }
        else {
            // Standard Rectangular Element
            g.append("rect")
              .attr("width", w).attr("height", h)
              .attr("fill", style.fill)
              .attr("opacity", style.opacity)
              .attr("stroke", style.stroke || 'none')
              .attr("stroke-width", style.strokeWidth || 0);

            // Zone Labels
            if (d.label || d.type.includes('zone') || [ElementType.BEDROOM_ZONE, ElementType.LIVING_ZONE, ElementType.KITCHEN_ZONE, ElementType.BATHROOM_ZONE].includes(d.type as ElementType)) {
                const labelText = d.label || (d.type as string).split('_').shift()?.toUpperCase();
                if (w > 30 && h > 20) {
                    g.append("text")
                     .attr("x", cx)
                     .attr("y", cy)
                     .attr("text-anchor", "middle")
                     .attr("dominant-baseline", "middle")
                     .attr("fill", "#94a3b8")
                     .attr("font-size", "8px")
                     .attr("font-weight", "bold")
                     .attr("pointer-events", "none")
                     .text(labelText || '');
                }
            }
        }

        // Highlight violations
        if (violations.some(v => v.elementId === d.id)) {
            g.append("rect")
             .attr("width", w)
             .attr("height", h)
             .attr("fill", "none")
             .attr("stroke", "#ef4444")
             .attr("stroke-width", 2)
             .style("stroke-dasharray", "4,2");
        }
      });

    const zoom = d3.zoom<SVGSVGElement, unknown>()
      .scaleExtent([0.1, 15])
      .on("zoom", (event) => mainGroup.attr("transform", event.transform));
    svg.call(zoom);

    if (svgRef.current?.parentElement) {
        const { clientWidth: pw, clientHeight: ph } = svgRef.current.parentElement;
        const scale = Math.min(pw / width, ph / height) * 0.9;
        svg.call(zoom.transform, d3.zoomIdentity.translate((pw - width * scale) / 2, (ph - height * scale) / 2).scale(scale));
    }
  }, [layout, violations]);

  return (
    <div className="w-full h-full bg-slate-950 rounded-lg overflow-hidden border border-slate-800 shadow-inner relative">
       <svg ref={svgRef} className="block cursor-grab active:cursor-grabbing w-full h-full" />
    </div>
  );
});

export default MapRenderer;

export enum ElementType {
  // --- 1. 基础结构与边界 (Structural & Boundary) ---
  SLAB = 'floor_slab',           // 楼板：定义层高和水平平面
  WALL_EXTERNAL = 'exterior_wall', // 外墙：定义建筑轮廓，不可随意改动
  WALL_INTERNAL = 'partition_wall',// 内隔墙：用于房间分隔
  SHEAR_WALL = 'shear_wall',     // 剪力墙：结构核心，生成逻辑中的硬约束
  PILLAR = 'pillar',             // 柱体：按轴网分布的结构点
  ROOF_PARAPET = 'parapet',      // 女儿墙：顶层边界实体

  // --- 2. 核心筒与垂直交通 (Core & Vertical Circulation) ---
  ELEVATOR_SHAFT = 'elevator_shaft', // 电梯井道：贯穿全层的垂直空腔
  STAIRCASE = 'staircase',           // 楼梯间：包含踏步、平台和扶手
  SERVICE_SHAFT = 'pipe_shaft',      // 管井：走水、电、烟道的垂直通道（决定厨卫位置）
  ELEVATOR_HALL = 'elevator_lobby',  // 电梯厅：垂直交通到水平交通的转换空间

  // --- 3. 水平交通 (Horizontal Circulation) ---
  CORRIDOR = 'corridor',         // 走廊/楼道：连接各房间的水平通路
  LOBBY = 'lobby',               // 门厅/大堂：公共区域的宏观节点
  AISLE = 'aisle',               // 室内过道：大房间内部的小型动线

  // --- 4. 洞口与连接 (Apertures & Connectors) ---
  DOOR = 'door',                 // 标准门：定义空间可达性 (Reachability)
  FIRE_DOOR = 'fire_door',       // 防火门：安全分区的连接点
  WINDOW = 'window',             // 窗户：影响采光率和功能房判定 (如卧室必须有窗)
  ENTRANCE = 'entrance',         // 楼层/建筑入口
  EXIT = 'exit',                 // 安全出口

  // --- 5. 外部延展与附件 (Extension & Attachments) ---
  BALCONY = 'balcony',           // 阳台：室内向外的延伸实体
  TERRACE = 'terrace',           // 露台：通常位于退台或顶层
  AIR_CON_LEDGE = 'ac_ledge',    // 空调位/设备平台：外部悬挂实体
  WINDOW_SILL = 'window_sill',   // 窗台：影响家具布置的实体细节

  // --- 6. 宏观功能分区 (Macro Functional Zones - 用于标注生成目标) ---
  // 注意：在宏观生成中，这些通常作为带标签的“空间实体”处理
  KITCHEN_ZONE = 'kitchen',      // 厨房：必须靠近管井
  BATHROOM_ZONE = 'bathroom',    // 卫生间：必须靠近管井
  LIVING_ZONE = 'living_room',   // 起居室：通常拥有最大的采光面
  BEDROOM_ZONE = 'bedroom',      // 卧室：私密空间，需考虑开窗
  STORAGE_ZONE = 'storage',      // 储藏间：无窗亦可的功能块

  // --- 7. 安全与基础设施末端 (Safety & MEP) ---
  FIRE_HYDRANT = 'fire_hydrant', // 消火栓：固定在走廊墙体的实体
  SAFE_EXIT_SIGN = 'exit_sign',  // 安全出口标识
  HVAC_VENT = 'hvac_vent',       // 通风口：影响天花板布局
  ELECTRICAL_BOX = 'dist_box',   // 配电箱：通常位于门口或走廊

  // --- 8. Legacy / Parking Elements (Compatibility) ---
  // These members are added to support legacy parking logic used in geometry and geminiService files.
  PARKING_SPACE = 'parking_space',
  WALL = 'wall',
  ROAD = 'road',
  RAMP = 'ramp',
  CHARGING_STATION = 'charging_station',
  FIRE_EXTINGUISHER = 'fire_extinguisher',
  GROUND = 'ground',
  SAFE_EXIT = 'safe_exit',
  GUIDANCE_SIGN = 'guidance_sign',
  SIDEWALK = 'sidewalk',
  SPEED_BUMP = 'speed_bump',
  LANE_LINE = 'lane_line',
  ELEVATOR = 'elevator'
}

export interface LayoutElement {
  id: string;
  type: ElementType | string; // Allow string for backward compatibility/flexibility
  x: number;
  y: number;
  width: number;
  height: number;
  rotation?: number; // Degrees
  label?: string;
  subType?: string; // For things like 'lane_line' direction
}

export interface ParkingLayout {
  width: number;
  height: number;
  elements: LayoutElement[];
}

export interface ConstraintViolation {
  elementId: string;
  targetId?: string; // If colliding with another element
  type: 'overlap' | 'out_of_bounds' | 'invalid_dimension' | 'placement_error' | 'connectivity_error' | 'width_mismatch';
  message: string;
}

import { GoogleGenAI } from "@google/genai";
import { jsonrepair } from "jsonrepair";
import { z } from "zod";
import { ParkingLayout, ElementType, ConstraintViolation, LayoutElement } from "../types";
import { validateLayout, getIntersectionBox } from "../utils/geometry";
import { PROMPTS } from "../utils/prompts";

const fallbackLayout: ParkingLayout = { width: 800, height: 600, elements: [] };

// Using Gemini 3 series models as per SDK guidelines for complex reasoning tasks.
const MODEL_PRIMARY = "gemini-3-pro-preview";
const MODEL_FALLBACK = "gemini-3-flash-preview"; 

let cachedTier: 'HIGH' | 'LOW' | null = null;

// API Key 必须从 process.env 获取，该变量会根据用户在对话框中的选择动态更新
const getApiKey = () => process.env.API_KEY;
const sleep = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

// --- ALGORITHM: GEOMETRIC PARKING SPOT FILLER ---
const fillParkingAutomatically = (layout: ParkingLayout): ParkingLayout => {
  const existingElements = [...layout.elements];
  const grounds = existingElements.filter(e => e.type === ElementType.GROUND);
  const roads = existingElements.filter(e => e.type === ElementType.ROAD);

  // Obstacles to avoid
  const obstacles = existingElements.filter(e => 
    [ElementType.WALL, ElementType.STAIRCASE, ElementType.ELEVATOR, ElementType.PILLAR,
     ElementType.ENTRANCE, ElementType.EXIT, ElementType.RAMP, ElementType.SAFE_EXIT,
     ElementType.SIDEWALK, ElementType.PARKING_SPACE].includes(e.type as ElementType)
  );

  const genSpots: LayoutElement[] = [];
  const SPOT_S = 24; // Width
  const SPOT_L = 48; // Length
  const GAP = 2;     // Space between spots
  const BUFFER = 4;  
  const TOLERANCE = 12; 

  const isSafe = (rect: {x: number, y: number, w: number, h: number}) => {
      const m = 1; 
      const hitObstacle = obstacles.some(o => 
        rect.x + m < o.x + o.width && rect.x + rect.w - m > o.x &&
        rect.y + m < o.y + o.height && rect.y + rect.h - m > o.y
      );
      const hitSelf = genSpots.some(o => 
        rect.x + m < o.x + o.width && rect.x + rect.w - m > o.x &&
        rect.y + m < o.y + o.height && rect.y + rect.h - m > o.y
      );
      return !hitObstacle && !hitSelf;
  };

  let t = 0; 

  roads.forEach(r => {
      const rr = { l: r.x, r: r.x + r.width, t: r.y, b: r.y + r.height };

      grounds.forEach(g => {
          const gr = { l: g.x, r: g.x + g.width, t: g.y, b: g.y + g.height };

          if (Math.abs(rr.b - gr.t) < TOLERANCE && Math.min(rr.r, gr.r) > Math.max(rr.l, gr.l)) {
               const sx = Math.max(rr.l, gr.l) + BUFFER;
               const ex = Math.min(rr.r, gr.r) - BUFFER;
               const cnt = Math.floor((ex - sx) / (SPOT_S + GAP)); 

               for(let i=0; i<cnt; i++) {
                   const s = { x: sx + i*(SPOT_S+GAP), y: gr.t + 1, w: SPOT_S, h: SPOT_L };
                   if (isSafe(s)) {
                       genSpots.push({ 
                           id: `p_auto_${++t}`, 
                           type: ElementType.PARKING_SPACE, 
                           x: s.x, y: s.y, width: s.w, height: s.h,
                           rotation: 0 
                       });
                   }
               }
          }
          else if (Math.abs(rr.t - gr.b) < TOLERANCE && Math.min(rr.r, gr.r) > Math.max(rr.l, gr.l)) {
              const sx = Math.max(rr.l, gr.l) + BUFFER;
              const ex = Math.min(rr.r, gr.r) - BUFFER;
              const cnt = Math.floor((ex - sx) / (SPOT_S + GAP));

              for(let i=0; i<cnt; i++) {
                   const s = { x: sx + i*(SPOT_S+GAP), y: gr.b - SPOT_L - 1, w: SPOT_S, h: SPOT_L };
                   if (isSafe(s)) {
                       genSpots.push({ 
                           id: `p_auto_${++t}`, 
                           type: ElementType.PARKING_SPACE, 
                           x: s.x, y: s.y, width: s.w, height: s.h,
                           rotation: 0 
                       });
                   }
              }
          }
          else if (Math.abs(rr.r - gr.l) < TOLERANCE && Math.min(rr.b, gr.b) > Math.max(rr.t, gr.t)) {
              const sy = Math.max(rr.t, gr.t) + BUFFER;
              const ey = Math.min(rr.b, gr.b) - BUFFER;
              const cnt = Math.floor((ey - sy) / (SPOT_S + GAP));

              for(let i=0; i<cnt; i++) {
                  const s = { x: gr.l + 1, y: sy + i*(SPOT_S+GAP), w: SPOT_L, h: SPOT_S };
                  if (isSafe(s)) {
                      genSpots.push({
                          id: `p_auto_v_${++t}`,
                          type: ElementType.PARKING_SPACE,
                          x: s.x, y: s.y, width: s.w, height: s.h,
                          rotation: 0
                      });
                  }
              }
          }
          else if (Math.abs(rr.l - gr.r) < TOLERANCE && Math.min(rr.b, gr.b) > Math.max(rr.t, gr.t)) {
              const sy = Math.max(rr.t, gr.t) + BUFFER;
              const ey = Math.min(rr.b, gr.b) - BUFFER;
              const cnt = Math.floor((ey - sy) / (SPOT_S + GAP));

              for(let i=0; i<cnt; i++) {
                  const s = { x: gr.r - SPOT_L - 1, y: sy + i*(SPOT_S+GAP), w: SPOT_L, h: SPOT_S };
                  if (isSafe(s)) {
                      genSpots.push({
                          id: `p_auto_v_${++t}`,
                          type: ElementType.PARKING_SPACE,
                          x: s.x, y: s.y, width: s.w, height: s.h,
                          rotation: 0
                      });
                  }
              }
          }
      });
  });

  return { ...layout, elements: [...existingElements, ...genSpots] };
};

// --- ALGORITHM: CHARGING STATION GENERATOR ---
const generateChargingStations = (layout: ParkingLayout): ParkingLayout => {
    const spots = layout.elements.filter(e => e.type === ElementType.PARKING_SPACE);
    const roads = layout.elements.filter(e => e.type === ElementType.ROAD);
    const stations: LayoutElement[] = [];

    const sortedSpots = [...spots].sort((a, b) => {
        if (Math.abs(a.y - b.y) < 10) return a.x - b.x; 
        return a.y - b.y;
    });

    let stationCount = 0;
    const STATION_SIZE = 10;
    const OFFSET = 2;

    sortedSpots.forEach((spot, index) => {
        if ((index + 1) % 3 === 0) {
            const candidates = [
                { x: spot.x + spot.width/2 - STATION_SIZE/2, y: spot.y + OFFSET, side: 'top' },
                { x: spot.x + spot.width/2 - STATION_SIZE/2, y: spot.y + spot.height - STATION_SIZE - OFFSET, side: 'bottom' },
                { x: spot.x + OFFSET, y: spot.y + spot.height/2 - STATION_SIZE/2, side: 'left' },
                { x: spot.x + spot.width - STATION_SIZE - OFFSET, y: spot.y + spot.height/2 - STATION_SIZE/2, side: 'right' }
            ];

            const isVerticalSpot = spot.height > spot.width;
            let validCandidates = candidates.filter(c => {
                 if (isVerticalSpot) return c.side === 'top' || c.side === 'bottom';
                 return c.side === 'left' || c.side === 'right';
            });

            let bestCandidate = validCandidates[0];
            let maxDistToRoad = -1;

            validCandidates.forEach(cand => {
                let minDistToRoad = Infinity;
                roads.forEach(r => {
                    const rcx = r.x + r.width / 2;
                    const rcy = r.y + r.height / 2;
                    const dist = Math.sqrt(Math.pow(cand.x - rcx, 2) + Math.pow(cand.y - rcy, 2));
                    if (dist < minDistToRoad) minDistToRoad = dist;
                });

                if (minDistToRoad > maxDistToRoad) {
                    maxDistToRoad = minDistToRoad;
                    bestCandidate = cand;
                }
            });

            if (bestCandidate) {
                stations.push({
                    id: `charging_${++stationCount}`,
                    type: ElementType.CHARGING_STATION,
                    x: bestCandidate.x,
                    y: bestCandidate.y,
                    width: STATION_SIZE,
                    height: STATION_SIZE,
                    rotation: 0
                });
            }
        }
    });

    return { ...layout, elements: [...layout.elements, ...stations] };
};

const cleanIntersections = (layout: ParkingLayout): ParkingLayout => {
    const roads = layout.elements.filter(e => e.type === ElementType.ROAD);
    let elementsToRemove = new Set<string>();

    for (let i = 0; i < roads.length; i++) {
        for (let j = i + 1; j < roads.length; j++) {
            const r1 = roads[i];
            const r2 = roads[j];
            const intersection = getIntersectionBox(r1, r2);

            if (intersection && intersection.width > 20 && intersection.height > 20) {
                const debris = layout.elements.filter(el => {
                    if (elementsToRemove.has(el.id)) return false;
                    const isDebrisType = [ElementType.LANE_LINE, ElementType.PARKING_SPACE, ElementType.SPEED_BUMP, ElementType.GUIDANCE_SIGN].includes(el.type as ElementType);
                    if (!isDebrisType) return false;

                    const cx = el.x + el.width / 2;
                    const cy = el.y + el.height / 2;
                    return cx > intersection.x && cx < intersection.x + intersection.width &&
                           cy > intersection.y && cy < intersection.y + intersection.height;
                });
                debris.forEach(d => elementsToRemove.add(d.id));
            }
        }
    }

    return elementsToRemove.size > 0 ? { ...layout, elements: layout.elements.filter(e => !elementsToRemove.has(e.id)) } : layout;
};

const cleanupPillars = (layout: ParkingLayout): ParkingLayout => {
    const roads = layout.elements.filter(e => e.type === ElementType.ROAD);
    const spots = layout.elements.filter(e => e.type === ElementType.PARKING_SPACE);

    return {
        ...layout,
        elements: layout.elements.filter(el => {
            if (el.type !== ElementType.PILLAR) return true;
            const isOnRoad = roads.some(r => el.x < r.x + r.width && el.x + el.width > r.x && el.y < r.y + r.height && el.y + el.height > r.y);
            const isInsideSpot = spots.some(s => el.x > s.x + 2 && el.x + el.width < s.x + s.width - 2 && el.y > s.y + 2 && el.y + el.height < s.y + s.height - 2);
            return !isOnRoad && !isInsideSpot;
        })
    };
};

const mergeLayoutElements = (original: LayoutElement[], updates: LayoutElement[]): LayoutElement[] => {
  const elementMap = new Map(original.map(el => [el.id, el]));
  updates.forEach(update => {
    if (update.id && elementMap.has(update.id)) {
      const existing = elementMap.get(update.id)!;
      elementMap.set(update.id, { ...existing, ...update });
    } else {
      const newId = update.id || `el_${Math.random().toString(36).substr(2, 9)}`;
      elementMap.set(newId, { ...update, id: newId });
    }
  });
  return Array.from(elementMap.values());
};

const postProcessLayout = (layout: ParkingLayout): ParkingLayout => {
    return {
        ...layout,
        elements: layout.elements.map(el => {
            const isStructural = [ElementType.ROAD, ElementType.GROUND, ElementType.WALL].includes(el.type as ElementType);
            const pad = isStructural ? 1 : 0;
            return { ...el, x: Math.round(el.x), y: Math.round(el.y), width: Math.round(el.width) + pad, height: Math.round(el.height) + pad };
        })
    };
};

const resolvePriorityConflicts = (elements: LayoutElement[]): LayoutElement[] => {
    const sidewalks = elements.filter(e => e.type === ElementType.SIDEWALK);
    return elements.filter(el => {
        if (el.type === ElementType.SPEED_BUMP) {
            const hasConflict = sidewalks.some(s => {
                const intersection = getIntersectionBox(el, s);
                return intersection !== null && (intersection.width > 2 || intersection.height > 2);
            });
            return !hasConflict;
        }
        return true;
    });
};

const orientGuidanceSigns = (layout: ParkingLayout): ParkingLayout => {
    const exits = layout.elements.filter(e => e.type === ElementType.EXIT);
    const roads = layout.elements.filter(e => e.type === ElementType.ROAD);
    if (exits.length === 0) return layout;

    const updated = layout.elements.map(el => {
        if (el.type === ElementType.GUIDANCE_SIGN) {
            const parentRoad = roads.find(r => el.x >= r.x - 5 && el.x + el.width <= r.x + r.width + 5 && el.y >= r.y - 5 && el.y + el.height <= r.y + r.height + 5);
            let nearestExit = exits[0], minDist = Infinity;
            const scx = el.x + el.width / 2;
            const scy = el.y + el.height / 2;
            exits.forEach(ex => {
                const ecx = ex.x + ex.width / 2;
                const ecy = ex.y + ex.height / 2;
                const d = Math.abs(ecx - scx) + Math.abs(ecy - scy);
                if (d < minDist) { minDist = d; nearestExit = ex; }
            });
            const ecx = nearestExit.x + nearestExit.width / 2;
            const ecy = nearestExit.y + nearestExit.height / 2;
            if (parentRoad) {
                const isHorizontal = parentRoad.width > parentRoad.height;
                return { ...el, rotation: isHorizontal ? (ecx > scx ? 0 : 180) : (ecy > scy ? 90 : 270) };
            }
            const dx = ecx - scx;
            const dy = ecy - scy;
            return Math.abs(dx) > Math.abs(dy) ? { ...el, rotation: dx > 0 ? 0 : 180 } : { ...el, rotation: dy > 0 ? 90 : 270 };
        }
        return el;
    });
    return { ...layout, elements: updated };
};

// 动态获取模型层级
async function determineModelTier(ai: GoogleGenAI, onLog?: (m: string) => void): Promise<'HIGH' | 'LOW'> {
    if (cachedTier) return cachedTier;
    onLog?.("Checking high-tier model availability...");
    try {
        await ai.models.generateContent({ model: MODEL_PRIMARY, contents: "test", config: { maxOutputTokens: 1 } });
        cachedTier = 'HIGH';
        onLog?.(`Model ${MODEL_PRIMARY} access confirmed.`);
    } catch (e: any) {
        onLog?.(`Primary model fallback to ${MODEL_FALLBACK}: ${e.message}`);
        cachedTier = 'LOW';
    }
    return cachedTier;
}

const normalizeType = (t: string | undefined): string => {
  if (!t) return ElementType.WALL;
  const lower = t.toLowerCase().trim().replace(/\s+/g, '_');
  const map: Record<string, string> = {
    'ramp': ElementType.RAMP, 'slope': ElementType.RAMP,
    'speed_bump': ElementType.SPEED_BUMP, 'deceleration_zone': ElementType.SPEED_BUMP,
    'road': ElementType.ROAD, 'driving_lane': ElementType.ROAD,
    'pedestrian_path': ElementType.SIDEWALK, 'sidewalk': ElementType.SIDEWALK,
    'ground_line': ElementType.LANE_LINE, 'lane_line': ElementType.LANE_LINE,
    'parking_spot': ElementType.PARKING_SPACE, 'parking': ElementType.PARKING_SPACE,
    'charging': ElementType.CHARGING_STATION, 'ground': ElementType.GROUND, 
    'island': ElementType.GROUND, 'landscape': ElementType.GROUND, 'pillar': ElementType.PILLAR,
    'ev_charging_zone': ElementType.CHARGING_STATION,
    'charging_zone': ElementType.CHARGING_STATION,
    'elevator_hall': ElementType.ELEVATOR,
    'elevator': ElementType.ELEVATOR,
    'staircase': ElementType.STAIRCASE,
    'stairs': ElementType.STAIRCASE,
    'fire_stairs': ElementType.STAIRCASE,
    'safe_exit': ElementType.SAFE_EXIT, 'fire_extinguisher': ElementType.FIRE_EXTINGUISHER,
    'guidance_sign': ElementType.GUIDANCE_SIGN, 'parking_strip': ElementType.GROUND,
    'central_island': ElementType.GROUND, 'green_zone': ElementType.GROUND,
    'landscape_area': ElementType.GROUND, 'void': ElementType.GROUND, 
    'buffer': ElementType.GROUND, 'median': ElementType.GROUND
  };
  return map[lower] || lower;
};

const cleanAndParseJSON = (text: string): any => {
  try {
    let cleanText = text.replace(/```json\s*|```/g, "").trim();
    const firstOpen = cleanText.indexOf('{');
    const lastClose = cleanText.lastIndexOf('}');
    if (firstOpen !== -1 && lastClose !== -1) cleanText = cleanText.substring(firstOpen, lastClose + 1);
    const repaired = jsonrepair(cleanText);
    return JSON.parse(repaired);
  } catch (e) {
    throw new Error(`AI 返回的数据格式有误: ${(e as Error).message}`);
  }
};

const mapToInternalLayout = (rawData: any): ParkingLayout => ({
    width: Number(rawData.width || 800),
    height: Number(rawData.height || 600),
    elements: (rawData.elements || []).map((e: any) => ({
        id: String(e.id || `el_${Math.random().toString(36).substr(2, 9)}`),
        type: normalizeType(e.t || e.type),
        x: Number(e.x || 0),
        y: Number(e.y || 0),
        width: Number(e.w ?? e.width ?? 10),
        height: Number(e.h ?? e.height ?? 10),
        rotation: Number(e.r || 0),
        label: e.l
    }))
});

const calculateScore = (violations: ConstraintViolation[]): number => {
    return violations.reduce((acc, v) => {
        if (v.type === 'overlap') return acc + 5;
        if (v.type === 'connectivity_error') return acc + 10;
        if (v.type === 'out_of_bounds') return acc + 8;
        return acc + 2;
    }, 0);
};

const generateWithRetry = async (ai: GoogleGenAI, params: any, retries = 3) => {
    for (let i = 0; i < retries; i++) {
        try {
            return await ai.models.generateContent(params);
        } catch (e: any) {
            if (e.message?.includes("429") && i < retries - 1) {
              await sleep(3000 * Math.pow(2, i));
              continue;
            }
            if (i === retries - 1) throw e;
        }
    }
    throw new Error("Failed after retries");
};

const runIterativeFix = async (layout: ParkingLayout, ai: GoogleGenAI, model: string, onLog?: (m: string) => void, maxPasses = 4): Promise<ParkingLayout> => {
    let currentLayout = layout;
    let lastScore = Infinity;

    for (let pass = 1; pass <= maxPasses; pass++) {
        const violations = validateLayout(currentLayout);
        const score = calculateScore(violations);

        if (score === 0) {
            onLog?.(`🔧 Pass ${pass}: 布局验证通过 (Score: 0).`);
            break;
        }
        if (score >= lastScore && pass > 1) {
            onLog?.(`🌡️ 迭代停滞于 Pass ${pass} (Score: ${score}).`);
            break;
        }

        onLog?.(`🔧 Auto-fixing pass ${pass}/${maxPasses} (Score: ${score})...`);
        lastScore = score;

        const simplified = {
            width: currentLayout.width,
            height: currentLayout.height,
            elements: currentLayout.elements.map(e => ({ id: e.id, t: e.type, x: Math.round(e.x), y: Math.round(e.y), w: Math.round(e.width), h: Math.round(e.height), r: e.rotation }))
        };

        try {
            const response = await generateWithRetry(ai, { 
                model, 
                contents: PROMPTS.fix(simplified as any, violations), 
                config: { responseMimeType: "application/json", temperature: 0.1 } 
            }, 1);

            const rawData = cleanAndParseJSON(response.text || "{}");
            if (rawData.fix_strategy && onLog) rawData.fix_strategy.forEach((s: string) => onLog(`🤖 AI Action: ${s}`));

            const fixedLayout = mapToInternalLayout(rawData);
            currentLayout = { ...currentLayout, elements: mergeLayoutElements(currentLayout.elements, fixedLayout.elements) };
        } catch (e: any) {
            onLog?.(`⚠️ 修复失败: ${e.message}`);
            break;
        }
    }
    return currentLayout;
};

export const generateParkingLayout = async (description: string, onLog?: (msg: string) => void): Promise<ParkingLayout> => {
  const apiKey = getApiKey();
  if (!apiKey) throw new Error("缺少 API Key。请点击 Key 图标进行设置。");

  const ai = new GoogleGenAI({ apiKey });
  let tier = await determineModelTier(ai, onLog);
  let currentModel = tier === 'HIGH' ? MODEL_PRIMARY : MODEL_FALLBACK;
  onLog?.(`Using model: ${currentModel}`);

  try {
    const response = await generateWithRetry(ai, { 
      model: currentModel, 
      contents: PROMPTS.generation(description), 
      config: { responseMimeType: "application/json" } 
    }, 2);

    const rawData = cleanAndParseJSON(response.text);
    if (rawData.reasoning_plan && onLog) onLog(`🧠 Plan: ${rawData.reasoning_plan}`);

    let layout = mapToInternalLayout(rawData);
    layout = await runIterativeFix(layout, ai, currentModel, onLog);
    return postProcessLayout(layout);
  } catch (error: any) {
    throw error;
  }
};

export const augmentLayoutWithRoads = async (currentLayout: ParkingLayout, onLog?: (msg: string) => void): Promise<ParkingLayout> => {
  const apiKey = getApiKey();
  if (!apiKey) throw new Error("缺少 API Key");

  const ai = new GoogleGenAI({ apiKey });
  let tier = await determineModelTier(ai, onLog);
  let currentModel = tier === 'HIGH' ? MODEL_PRIMARY : MODEL_FALLBACK;

  try {
    const simplified = currentLayout.elements.map(e => ({ id: e.id, t: e.type, x: e.x, y: e.y, w: e.width, h: e.height }));
    const response = await generateWithRetry(ai, { 
        model: currentModel, 
        contents: PROMPTS.refinement({ elements: simplified }, currentLayout.width, currentLayout.height), 
        config: { responseMimeType: "application/json" } 
    }, 2);

    const rawData = cleanAndParseJSON(response.text);
    if (rawData.reasoning_plan && onLog) onLog(`✨ AI Plan: ${rawData.reasoning_plan}`);

    const aiGeneratedLayout = mapToInternalLayout(rawData);
    let layout: ParkingLayout = { width: currentLayout.width, height: currentLayout.height, elements: [...currentLayout.elements, ...aiGeneratedLayout.elements] };

    onLog?.("📐 执行几何填充算法...");
    layout = fillParkingAutomatically(layout);
    layout = cleanIntersections(layout);
    layout = generateChargingStations(layout); 
    layout = cleanupPillars(layout);
    layout = cleanIntersections(layout);

    onLog?.("⚖️ 处理冲突与标线校准...");
    layout.elements = resolvePriorityConflicts(layout.elements);
    layout = orientGuidanceSigns(layout);

    layout = await runIterativeFix(layout, ai, currentModel, onLog);
    return postProcessLayout(layout);
  } catch (error: any) {
    throw error;
  }
};

