import { LayoutElement, ParkingLayout, ConstraintViolation, ElementType } from '../types';

// --- SPATIAL PARTITIONING SYSTEM ---
class SpatialGrid {
    private grid = new Map<string, LayoutElement[]>();
    private cellSize: number;

    constructor(cellSize = 100) {
        this.cellSize = cellSize;
    }

    private getKeysForElement(el: LayoutElement): string[] {
        const startX = Math.floor(el.x / this.cellSize);
        const endX = Math.floor((el.x + el.width) / this.cellSize);
        const startY = Math.floor(el.y / this.cellSize);
        const endY = Math.floor((el.y + el.height) / this.cellSize);

        const keys: string[] = [];
        for (let x = startX; x <= endX; x++) {
            for (let y = startY; y <= endY; y++) {
                keys.push(`${x},${y}`);
            }
        }
        return keys;
    }

    add(el: LayoutElement) {
        const keys = this.getKeysForElement(el);
        keys.forEach(key => {
            if (!this.grid.has(key)) {
                this.grid.set(key, []);
            }
            this.grid.get(key)!.push(el);
        });
    }

    getPotentialCollisions(el: LayoutElement): LayoutElement[] {
        const keys = this.getKeysForElement(el);
        const candidates = new Set<LayoutElement>();

        keys.forEach(key => {
            const cell = this.grid.get(key);
            if (cell) {
                cell.forEach(candidate => {
                    if (candidate.id !== el.id) {
                        candidates.add(candidate);
                    }
                });
            }
        });

        return Array.from(candidates);
    }
}

// --- GEOMETRY UTILS ---
const EPSILON = 1.5;

function getCorners(el: LayoutElement): {x: number, y: number}[] {
    const rad = ((el.rotation || 0) * Math.PI) / 180;
    const cx = el.x + el.width / 2;
    const cy = el.y + el.height / 2;

    return [
        { x: el.x, y: el.y },
        { x: el.x + el.width, y: el.y },
        { x: el.x + el.width, y: el.y + el.height },
        { x: el.x, y: el.y + el.height },
    ].map(p => {
        const dx = p.x - cx;
        const dy = p.y - cy;
        return {
            x: cx + dx * Math.cos(rad) - dy * Math.sin(rad),
            y: cy + dx * Math.sin(rad) + dy * Math.cos(rad),
        };
    });
}

export function getIntersectionBox(r1: LayoutElement, r2: LayoutElement) {
    const x1 = Math.max(r1.x, r2.x);
    const y1 = Math.max(r1.y, r2.y);
    const x2 = Math.min(r1.x + r1.width, r2.x + r2.width);
    const y2 = Math.min(r1.y + r1.height, r2.y + r2.height);

    const width = x2 - x1;
    const height = y2 - y1;

    if (width > 0 && height > 0) {
        return { x: x1, y: y1, width, height };
    }
    return null;
}

function isTouching(a: LayoutElement, b: LayoutElement, margin = 2.0): boolean {
    const aRect = { l: a.x - margin, r: a.x + a.width + margin, t: a.y - margin, b: a.y + a.height + margin };
    const bRect = { l: b.x - margin, r: b.x + b.width + margin, t: b.y - margin, b: b.y + b.height + margin };

    const overlapX = Math.min(aRect.r, bRect.r) - Math.max(aRect.l, bRect.l);
    const overlapY = Math.min(aRect.b, bRect.b) - Math.max(aRect.t, bRect.t);

    return overlapX >= 0 && overlapY >= 0;
}

function isPointCovered(x: number, y: number, elements: LayoutElement[], padding = 10): boolean {
    return elements.some(el => 
        x >= el.x - padding && x <= el.x + el.width + padding &&
        y >= el.y - padding && y <= el.y + el.height + padding
    );
}

export function validateLayout(layout: ParkingLayout): ConstraintViolation[] {
  const violations: ConstraintViolation[] = [];
  if (!layout || !layout.elements) return violations;

  const grid = new SpatialGrid(100);
  layout.elements.forEach(el => grid.add(el));

  // 1. Out of Bounds
  layout.elements.forEach(el => {
    if (el.x < -EPSILON || el.x + el.width > layout.width + EPSILON || el.y < -EPSILON || el.y + el.height > layout.height + EPSILON) {
        violations.push({
            elementId: el.id,
            type: 'out_of_bounds',
            message: `Element '${el.type}' is outside boundary.`
        });
    }
  });

  // 2. Overlap Checks (Architectural Logic)
  const solidStructure = new Set([
    ElementType.WALL_EXTERNAL, ElementType.WALL_INTERNAL, ElementType.SHEAR_WALL, 
    ElementType.PILLAR, ElementType.ELEVATOR_SHAFT, ElementType.STAIRCASE, ElementType.SERVICE_SHAFT
  ]);

  const zones = new Set([
      ElementType.LIVING_ZONE, ElementType.BEDROOM_ZONE, ElementType.KITCHEN_ZONE, 
      ElementType.BATHROOM_ZONE, ElementType.STORAGE_ZONE, ElementType.CORRIDOR, ElementType.LOBBY
  ]);

  layout.elements.forEach(el1 => {
      const candidates = grid.getPotentialCollisions(el1);
      candidates.forEach(el2 => {
          if (el1.id >= el2.id) return; 

          // Zones should not overlap each other
          if (zones.has(el1.type as ElementType) && zones.has(el2.type as ElementType)) {
              const box = getIntersectionBox(el1, el2);
              if (box && box.width > 2 && box.height > 2) {
                  violations.push({
                      elementId: el1.id, targetId: el2.id, type: 'overlap',
                      message: `Zones overlap: ${el1.type} vs ${el2.type}`
                  });
              }
          }

          // Structural elements overlap check
          if (solidStructure.has(el1.type as ElementType) && solidStructure.has(el2.type as ElementType)) {
              // Internal walls can meet, but large overlaps are bad
              const box = getIntersectionBox(el1, el2);
              if (box) {
                  const area = box.width * box.height;
                  const minArea = Math.min(el1.width * el1.height, el2.width * el2.height);
                  if (area > minArea * 0.5) { // Major structural overlap
                      violations.push({
                          elementId: el1.id, targetId: el2.id, type: 'overlap',
                          message: `Structural conflict: ${el1.type} overlaps significantly with ${el2.type}`
                      });
                  }
              }
          }
      });
  });

  // 3. Opening Constraints (Windows & Doors)
  const extWalls = layout.elements.filter(e => e.type === ElementType.WALL_EXTERNAL);
  const corridors = layout.elements.filter(e => e.type === ElementType.CORRIDOR || e.type === ElementType.LOBBY);

  layout.elements.forEach(item => {
      if (item.type === ElementType.WINDOW) {
          const isOnExtWall = extWalls.some(wall => isTouching(wall, item, 5));
          if (!isOnExtWall) {
              violations.push({
                  elementId: item.id, type: 'placement_error',
                  message: `Window must be placed on an exterior wall.`
              });
          }
      }

      if (item.type === ElementType.DOOR || item.type === ElementType.FIRE_DOOR) {
          const connectsToCirculation = corridors.some(corr => isTouching(corr, item, 5));
          const connectsToRoom = layout.elements.some(el => zones.has(el.type as ElementType) && el.type !== ElementType.CORRIDOR && isTouching(el, item, 5));

          if (!connectsToCirculation && !connectsToRoom) {
              violations.push({
                  elementId: item.id, type: 'connectivity_error',
                  message: `Door is floating. It must connect a room to a corridor or lobby.`
              });
          }
      }
  });

  // 4. Room Functionality Checks
  const bedrooms = layout.elements.filter(e => e.type === ElementType.BEDROOM_ZONE || e.type === ElementType.LIVING_ZONE);
  bedrooms.forEach(room => {
      const hasWindow = layout.elements.some(el => el.type === ElementType.WINDOW && isTouching(el, room, 5));
      if (!hasWindow) {
          violations.push({
              elementId: room.id, type: 'placement_error',
              message: `${room.type} lacks a window. Primary rooms require natural light.`
          });
      }
      const hasDoor = layout.elements.some(el => (el.type === ElementType.DOOR || el.type === ElementType.FIRE_DOOR) && isTouching(el, room, 5));
      if (!hasDoor) {
          violations.push({
              elementId: room.id, type: 'connectivity_error',
              message: `${room.type} is inaccessible. Add a door.`
          });
      }
  });

  // 5. Perimeter Shell Check
  const corners = [
      { x: 0, y: 0, label: "Top-Left" },
      { x: layout.width, y: 0, label: "Top-Right" },
      { x: layout.width, y: layout.height, label: "Bottom-Right" },
      { x: 0, y: layout.height, label: "Bottom-Left" }
  ];
  corners.forEach(pt => {
      if (!isPointCovered(pt.x, pt.y, extWalls, 15)) {
          violations.push({
              elementId: `wall_gap_${pt.label}`,
              type: 'connectivity_error',
              message: `Building shell is broken at ${pt.label}. Exterior walls must form a closed loop.`
          });
      }
  });

  return violations;
}

import { GoogleGenAI } from "@google/genai";
import { jsonrepair } from "jsonrepair";
import { z } from "zod";
import { ParkingLayout, ElementType, ConstraintViolation, LayoutElement } from "../types";
import { validateLayout, getIntersectionBox } from "../utils/geometry";
import { PROMPTS } from "../utils/prompts";

const fallbackLayout: ParkingLayout = { width: 800, height: 600, elements: [] };

// Using Gemini 3 series models as per SDK guidelines for complex reasoning tasks.
const MODEL_PRIMARY = "gemini-3-pro-preview";
const MODEL_FALLBACK = "gemini-3-flash-preview"; 

let cachedTier: 'HIGH' | 'LOW' | null = null;

const getApiKey = () => process.env.API_KEY;
const sleep = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

// --- ALGORITHM: PILLAR GRID GENERATOR (Architectural) ---
const alignPillarsToGrid = (layout: ParkingLayout): ParkingLayout => {
  const pillars = layout.elements.filter(e => e.type === ElementType.PILLAR);
  const otherElements = layout.elements.filter(e => e.type !== ElementType.PILLAR);

  const GRID_SIZE = 100;

  const alignedPillars = pillars.map(p => {
    return {
      ...p,
      x: Math.round(p.x / GRID_SIZE) * GRID_SIZE,
      y: Math.round(p.y / GRID_SIZE) * GRID_SIZE
    };
  });

  return { ...layout, elements: [...otherElements, ...alignedPillars] };
};

const mergeLayoutElements = (original: LayoutElement[], updates: LayoutElement[]): LayoutElement[] => {
  const elementMap = new Map(original.map(el => [el.id, el]));
  updates.forEach(update => {
    if (update.id && elementMap.has(update.id)) {
      const existing = elementMap.get(update.id)!;
      elementMap.set(update.id, { ...existing, ...update });
    } else {
      const newId = update.id || `el_${Math.random().toString(36).substr(2, 9)}`;
      elementMap.set(newId, { ...update, id: newId });
    }
  });
  return Array.from(elementMap.values());
};

const postProcessLayout = (layout: ParkingLayout): ParkingLayout => {
    return {
        ...layout,
        elements: layout.elements.map(el => ({
            ...el,
            x: Math.round(el.x),
            y: Math.round(el.y),
            width: Math.round(el.width),
            height: Math.round(el.height)
        }))
    };
};

async function determineModelTier(ai: GoogleGenAI, onLog?: (m: string) => void): Promise<'HIGH' | 'LOW'> {
    if (cachedTier) return cachedTier;
    onLog?.("Checking high-tier model availability...");
    try {
        await ai.models.generateContent({ model: MODEL_PRIMARY, contents: "test", config: { maxOutputTokens: 1 } });
        cachedTier = 'HIGH';
        onLog?.(`Model ${MODEL_PRIMARY} access confirmed.`);
    } catch (e: any) {
        onLog?.(`Primary model fallback to ${MODEL_FALLBACK}: ${e.message}`);
        cachedTier = 'LOW';
    }
    return cachedTier;
}

const normalizeType = (t: string | undefined): string => {
  if (!t) return ElementType.WALL_INTERNAL;
  const lower = t.toLowerCase().trim().replace(/\s+/g, '_');
  const map: Record<string, string> = {
    'exterior_wall': ElementType.WALL_EXTERNAL, 'outer_wall': ElementType.WALL_EXTERNAL,
    'partition_wall': ElementType.WALL_INTERNAL, 'inner_wall': ElementType.WALL_INTERNAL,
    'slab': ElementType.SLAB, 'floor': ElementType.SLAB,
    'pillar': ElementType.PILLAR, 'column': ElementType.PILLAR,
    'elevator': ElementType.ELEVATOR_SHAFT, 'staircase': ElementType.STAIRCASE,
    'corridor': ElementType.CORRIDOR, 'hallway': ElementType.CORRIDOR,
    'living_room': ElementType.LIVING_ZONE, 'bedroom': ElementType.BEDROOM_ZONE,
    'kitchen': ElementType.KITCHEN_ZONE, 'bathroom': ElementType.BATHROOM_ZONE,
    'door': ElementType.DOOR, 'window': ElementType.WINDOW,
    'pipe_shaft': ElementType.SERVICE_SHAFT, 'shaft': ElementType.SERVICE_SHAFT,
    'entrance': ElementType.ENTRANCE, 'exit': ElementType.EXIT
  };
  return map[lower] || lower;
};

const cleanAndParseJSON = (text: string): any => {
  try {
    let cleanText = text.replace(/```json\s*|```/g, "").trim();
    const firstOpen = cleanText.indexOf('{');
    const lastClose = cleanText.lastIndexOf('}');
    if (firstOpen !== -1 && lastClose !== -1) cleanText = cleanText.substring(firstOpen, lastClose + 1);
    const repaired = jsonrepair(cleanText);
    return JSON.parse(repaired);
  } catch (e) {
    throw new Error(`AI parse error: ${(e as Error).message}`);
  }
};

const mapToInternalLayout = (rawData: any): ParkingLayout => ({
    width: Number(rawData.width || 800),
    height: Number(rawData.height || 600),
    elements: (rawData.elements || []).map((e: any) => ({
        id: String(e.id || `el_${Math.random().toString(36).substr(2, 9)}`),
        type: normalizeType(e.t || e.type),
        x: Number(e.x || 0),
        y: Number(e.y || 0),
        width: Number(e.w ?? e.width ?? 10),
        height: Number(e.h ?? e.height ?? 10),
        rotation: Number(e.r || 0),
        label: e.l
    }))
});

const calculateScore = (violations: ConstraintViolation[]): number => {
    return violations.reduce((acc, v) => {
        if (v.type === 'overlap') return acc + 5;
        if (v.type === 'connectivity_error') return acc + 10;
        if (v.type === 'out_of_bounds') return acc + 8;
        return acc + 2;
    }, 0);
};

const generateWithRetry = async (ai: GoogleGenAI, params: any, retries = 3) => {
    for (let i = 0; i < retries; i++) {
        try {
            return await ai.models.generateContent(params);
        } catch (e: any) {
            if (e.message?.includes("429") && i < retries - 1) {
              await sleep(3000 * Math.pow(2, i));
              continue;
            }
            if (i === retries - 1) throw e;
        }
    }
    throw new Error("Failed after retries");
};

const runIterativeFix = async (layout: ParkingLayout, ai: GoogleGenAI, model: string, onLog?: (m: string) => void, maxPasses = 4): Promise<ParkingLayout> => {
    let currentLayout = layout;
    let lastScore = Infinity;

    for (let pass = 1; pass <= maxPasses; pass++) {
        const violations = validateLayout(currentLayout);
        const score = calculateScore(violations);

        if (score === 0) {
            onLog?.(`🔧 Pass ${pass}: Layout valid (Score: 0).`);
            break;
        }
        if (score >= lastScore && pass > 1) {
            onLog?.(`🌡️ Fix loop stagnated at Pass ${pass} (Score: ${score}).`);
            break;
        }

        onLog?.(`🔧 Auto-fixing pass ${pass}/${maxPasses} (Score: ${score})...`);
        lastScore = score;

        const simplified = {
            width: currentLayout.width,
            height: currentLayout.height,
            elements: currentLayout.elements.map(e => ({ id: e.id, t: e.type, x: Math.round(e.x), y: Math.round(e.y), w: Math.round(e.width), h: Math.round(e.height), r: e.rotation }))
        };

        try {
            const response = await generateWithRetry(ai, { 
                model, 
                contents: PROMPTS.fix(simplified as any, violations), 
                config: { responseMimeType: "application/json", temperature: 0.1 } 
            }, 1);

            const rawData = cleanAndParseJSON(response.text || "{}");
            if (rawData.fix_strategy && onLog) rawData.fix_strategy.forEach((s: string) => onLog(`🤖 AI Fix: ${s}`));

            const fixedLayout = mapToInternalLayout(rawData);
            currentLayout = { ...currentLayout, elements: mergeLayoutElements(currentLayout.elements, fixedLayout.elements) };
        } catch (e: any) {
            onLog?.(`⚠️ Fix failed: ${e.message}`);
            break;
        }
    }
    return currentLayout;
};

export const generateParkingLayout = async (description: string, onLog?: (msg: string) => void): Promise<ParkingLayout> => {
  const apiKey = getApiKey();
  if (!apiKey) throw new Error("Missing API Key.");

  const ai = new GoogleGenAI({ apiKey });
  let tier = await determineModelTier(ai, onLog);
  let currentModel = tier === 'HIGH' ? MODEL_PRIMARY : MODEL_FALLBACK;

  try {
    const response = await generateWithRetry(ai, { 
      model: currentModel, 
      contents: PROMPTS.generation(description), 
      config: { responseMimeType: "application/json" } 
    }, 2);

    const rawData = cleanAndParseJSON(response.text);
    if (rawData.reasoning_plan && onLog) onLog(`🧠 Plan: ${rawData.reasoning_plan}`);

    let layout = mapToInternalLayout(rawData);
    layout = await runIterativeFix(layout, ai, currentModel, onLog);
    return postProcessLayout(layout);
  } catch (error: any) {
    throw error;
  }
};

export const augmentLayoutWithRoads = async (currentLayout: ParkingLayout, onLog?: (msg: string) => void): Promise<ParkingLayout> => {
  const apiKey = getApiKey();
  if (!apiKey) throw new Error("Missing API Key");

  const ai = new GoogleGenAI({ apiKey });
  let tier = await determineModelTier(ai, onLog);
  let currentModel = tier === 'HIGH' ? MODEL_PRIMARY : MODEL_FALLBACK;

  try {
    const simplified = currentLayout.elements.map(e => ({ id: e.id, t: e.type, x: e.x, y: e.y, w: e.width, h: e.height }));
    const response = await generateWithRetry(ai, { 
        model: currentModel, 
        contents: PROMPTS.refinement({ elements: simplified }, currentLayout.width, currentLayout.height), 
        config: { responseMimeType: "application/json" } 
    }, 2);

    const rawData = cleanAndParseJSON(response.text);
    if (rawData.reasoning_plan && onLog) onLog(`✨ AI Detail Plan: ${rawData.reasoning_plan}`);

    const detailLayout = mapToInternalLayout(rawData);
    let layout: ParkingLayout = { ...currentLayout, elements: [...currentLayout.elements, ...detailLayout.elements] };

    onLog?.("📐 Aligning structural pillars...");
    layout = alignPillarsToGrid(layout);

    layout = await runIterativeFix(layout, ai, currentModel, onLog);
    return postProcessLayout(layout);
  } catch (error: any) {
    throw error;
  }
};

