import React, { useEffect, useRef, forwardRef, useImperativeHandle } from 'react';
import * as d3 from 'd3';
import { ElementType, LayoutElement } from '../types';
import { useStore } from '../store';

const ELEMENT_STYLES: Record<string, { fill: string; opacity: number; stroke?: string; strokeWidth?: number }> = {
  // Structure
  [ElementType.SLAB]: { fill: '#0f172a', opacity: 1 },
  [ElementType.WALL_EXTERNAL]: { fill: '#f1f5f9', opacity: 1 },
  [ElementType.WALL_INTERNAL]: { fill: '#94a3b8', opacity: 1 },
  [ElementType.SHEAR_WALL]: { fill: '#cbd5e1', opacity: 1 },
  [ElementType.PILLAR]: { fill: '#f1f5f9', opacity: 1 },

  // Circulation
  [ElementType.CORRIDOR]: { fill: '#1e293b', opacity: 0.6, stroke: '#334155', strokeWidth: 1 },
  [ElementType.LOBBY]: { fill: '#1e293b', opacity: 0.8, stroke: '#334155', strokeWidth: 1 },
  [ElementType.AISLE]: { fill: '#1e293b', opacity: 0.5 },

  // Core
  [ElementType.ELEVATOR_SHAFT]: { fill: '#334155', opacity: 1 },
  [ElementType.STAIRCASE]: { fill: '#334155', opacity: 1 },
  [ElementType.SERVICE_SHAFT]: { fill: '#0f172a', opacity: 1, stroke: '#475569', strokeWidth: 1 },
  [ElementType.ELEVATOR_HALL]: { fill: '#1e293b', opacity: 0.9 },

  // Zones
  [ElementType.LIVING_ZONE]: { fill: '#3b82f6', opacity: 0.15, stroke: '#3b82f6', strokeWidth: 0.5 },
  [ElementType.BEDROOM_ZONE]: { fill: '#8b5cf6', opacity: 0.15, stroke: '#8b5cf6', strokeWidth: 0.5 },
  [ElementType.KITCHEN_ZONE]: { fill: '#f59e0b', opacity: 0.15, stroke: '#f59e0b', strokeWidth: 0.5 },
  [ElementType.BATHROOM_ZONE]: { fill: '#10b981', opacity: 0.15, stroke: '#10b981', strokeWidth: 0.5 },
  [ElementType.STORAGE_ZONE]: { fill: '#64748b', opacity: 0.15, stroke: '#64748b', strokeWidth: 0.5 },

  // Openings
  [ElementType.DOOR]: { fill: '#f1f5f9', opacity: 1 },
  [ElementType.FIRE_DOOR]: { fill: '#ef4444', opacity: 1 },
  [ElementType.WINDOW]: { fill: '#38bdf8', opacity: 0.4, stroke: '#38bdf8', strokeWidth: 2 },

  // MEP & Safety
  [ElementType.FIRE_HYDRANT]: { fill: '#ef4444', opacity: 1 },
  [ElementType.SAFE_EXIT_SIGN]: { fill: '#22c55e', opacity: 1 },
  [ElementType.HVAC_VENT]: { fill: '#94a3b8', opacity: 0.5 },
  [ElementType.ELECTRICAL_BOX]: { fill: '#eab308', opacity: 1 }
};

export interface MapRendererHandle {
  downloadJpg: () => void;
}

const MapRenderer = forwardRef<MapRendererHandle>((props, ref) => {
  const svgRef = useRef<SVGSVGElement>(null);
  const { layout, violations } = useStore();

  useImperativeHandle(ref, () => ({
    downloadJpg: () => {
      if (!svgRef.current || !layout) return;
      const svgNode = svgRef.current;
      const zoomGroup = d3.select(svgNode).select("g.main-group");
      const prevTransform = zoomGroup.attr("transform");
      zoomGroup.attr("transform", null); 
      svgNode.setAttribute("width", layout.width.toString());
      svgNode.setAttribute("height", layout.height.toString());
      svgNode.setAttribute("viewBox", `0 0 ${layout.width} ${layout.height}`);

      const serializer = new XMLSerializer();
      let svgString = serializer.serializeToString(svgNode);
      if (!svgString.match(/^<svg[^>]+xmlns="http\:\/\/www\.w3\.org\/2000\/svg"/)) {
        svgString = svgString.replace(/^<svg/, '<svg xmlns="http://www.w3.org/2000/svg"');
      }

      if (prevTransform) zoomGroup.attr("transform", prevTransform);

      const img = new Image();
      img.onload = () => {
        const canvas = document.createElement("canvas");
        canvas.width = layout.width;
        canvas.height = layout.height;
        const ctx = canvas.getContext("2d");
        if (ctx) {
          ctx.imageSmoothingEnabled = false; 
          ctx.fillStyle = "#0f172a"; 
          ctx.fillRect(0, 0, canvas.width, canvas.height);
          ctx.drawImage(img, 0, 0);
          const jpgUrl = canvas.toDataURL("image/jpeg", 0.98);
          const link = document.createElement("a");
          link.download = `floor_plan_${Date.now()}.jpg`;
          link.href = jpgUrl;
          document.body.appendChild(link);
          link.click();
          document.body.removeChild(link);
        }
      };
      img.src = "data:image/svg+xml;base64," + btoa(unescape(encodeURIComponent(svgString)));
    }
  }));

  useEffect(() => {
    if (!layout || !svgRef.current) return;
    const svg = d3.select(svgRef.current);
    svg.selectAll("*").remove(); 

    const { width, height, elements } = layout;
    svg.attr("viewBox", `0 0 ${width} ${height}`)
       .attr("width", "100%")
       .attr("height", "100%")
       .style("shape-rendering", "geometricPrecision"); 

    const mainGroup = svg.append("g").attr("class", "main-group");

    // Updated Architectural Z-Order
    const zOrder = [
        ElementType.SLAB,
        ElementType.LIVING_ZONE,
        ElementType.BEDROOM_ZONE,
        ElementType.KITCHEN_ZONE,
        ElementType.BATHROOM_ZONE,
        ElementType.STORAGE_ZONE,
        ElementType.CORRIDOR,
        ElementType.LOBBY,
        ElementType.AISLE,
        ElementType.ELEVATOR_HALL,
        ElementType.SERVICE_SHAFT,
        ElementType.STAIRCASE,
        ElementType.ELEVATOR_SHAFT,
        ElementType.WALL_INTERNAL,
        ElementType.SHEAR_WALL,
        ElementType.WALL_EXTERNAL,
        ElementType.PILLAR,
        ElementType.WINDOW,
        ElementType.DOOR,
        ElementType.FIRE_DOOR,
        ElementType.FIRE_HYDRANT,
        ElementType.SAFE_EXIT_SIGN,
        ElementType.ELECTRICAL_BOX
    ];

    const sortedElements = [...elements].sort((a, b) => {
      const idxA = zOrder.indexOf(a.type as ElementType);
      const idxB = zOrder.indexOf(b.type as ElementType);
      return (idxA === -1 ? 999 : idxA) - (idxB === -1 ? 999 : idxB);
    });

    mainGroup.selectAll("g.element")
      .data(sortedElements)
      .enter()
      .append("g")
      .attr("class", "element")
      .attr("transform", d => {
          const rotation = d.rotation || 0;
          return `translate(${d.x}, ${d.y}) rotate(${rotation}, ${d.width/2}, ${d.height/2})`;
      })
      .each(function(this: any, d) {
        const g = d3.select(this);
        const style = ELEMENT_STYLES[d.type as string] || { fill: '#ff00ff', opacity: 0.5 };
        const w = d.width;
        const h = d.height;
        const cx = w / 2;
        const cy = h / 2;

        if (d.type === ElementType.WINDOW) {
            // Render Window as glass pane
            g.append("rect")
             .attr("width", w)
             .attr("height", h)
             .attr("fill", style.fill)
             .attr("opacity", style.opacity)
             .attr("stroke", style.stroke || 'none')
             .attr("stroke-width", style.strokeWidth || 0);

            // Middle pane line
            const isHorizontal = w > h;
            g.append("line")
             .attr("x1", isHorizontal ? 0 : cx).attr("y1", isHorizontal ? cy : 0)
             .attr("x2", isHorizontal ? w : cx).attr("y2", isHorizontal ? h : cy)
             .attr("stroke", "#fff").attr("stroke-width", 0.5).attr("opacity", 0.8);
        } 
        else if (d.type === ElementType.STAIRCASE) {
            // Render Stairs with steps
            g.append("rect").attr("width", w).attr("height", h).attr("fill", style.fill).attr("opacity", 1);
            const isHorizontal = w > h;
            const stepSize = 8;
            const stepCount = Math.floor((isHorizontal ? w : h) / stepSize);

            for(let i=1; i<stepCount; i++) {
                g.append("line")
                 .attr("x1", isHorizontal ? i * stepSize : 0).attr("y1", isHorizontal ? 0 : i * stepSize)
                 .attr("x2", isHorizontal ? i * stepSize : w).attr("y2", isHorizontal ? h : i * stepSize)
                 .attr("stroke", "#0f172a").attr("stroke-width", 1);
            }

            // Direction Arrow
            const arrowSize = Math.min(w, h) * 0.3;
            g.append("path")
             .attr("d", isHorizontal ? `M 10 ${cy} L ${w-10} ${cy} M ${w-20} ${cy-5} L ${w-10} ${cy} L ${w-20} ${cy+5}` : `M ${cx} 10 L ${cx} ${h-10} M ${cx-5} ${h-20} L ${cx} ${h-10} L ${cx+5} ${h-20}`)
             .attr("stroke", "#f1f5f9").attr("fill", "none").attr("stroke-width", 1.5);
        }
        else if (d.type === ElementType.DOOR || d.type === ElementType.FIRE_DOOR) {
            // Render Door swing arc
            const rotation = d.rotation || 0;
            const isFire = d.type === ElementType.FIRE_DOOR;

            g.append("rect")
             .attr("width", w)
             .attr("height", h)
             .attr("fill", isFire ? '#ef4444' : '#f1f5f9')
             .attr("rx", 1);

            // Simple swing arc visualization
            const arcRadius = Math.max(w, h);
            g.append("path")
             .attr("d", `M 0 0 A ${arcRadius} ${arcRadius} 0 0 1 ${arcRadius} ${arcRadius}`)
             .attr("fill", "none")
             .attr("stroke", style.fill)
             .attr("stroke-dasharray", "2,2")
             .attr("opacity", 0.5)
             .attr("transform", `translate(0, 0) scale(${w/arcRadius}, ${h/arcRadius})`);
        }
        else if (d.type === ElementType.PILLAR) {
            g.append("rect")
             .attr("width", w).attr("height", h)
             .attr("fill", style.fill)
             .attr("stroke", "#0f172a")
             .attr("stroke-width", 1);
        }
        else {
            // Standard Rectangular Element
            g.append("rect")
              .attr("width", w).attr("height", h)
              .attr("fill", style.fill)
              .attr("opacity", style.opacity)
              .attr("stroke", style.stroke || 'none')
              .attr("stroke-width", style.strokeWidth || 0);

            // Zone Labels
            if (d.label || d.type.includes('zone') || [ElementType.BEDROOM_ZONE, ElementType.LIVING_ZONE, ElementType.KITCHEN_ZONE, ElementType.BATHROOM_ZONE].includes(d.type as ElementType)) {
                const labelText = d.label || (d.type as string).split('_').shift()?.toUpperCase();
                if (w > 30 && h > 20) {
                    g.append("text")
                     .attr("x", cx)
                     .attr("y", cy)
                     .attr("text-anchor", "middle")
                     .attr("dominant-baseline", "middle")
                     .attr("fill", "#94a3b8")
                     .attr("font-size", "8px")
                     .attr("font-weight", "bold")
                     .attr("pointer-events", "none")
                     .text(labelText || '');
                }
            }
        }

        // Highlight violations
        if (violations.some(v => v.elementId === d.id)) {
            g.append("rect")
             .attr("width", w)
             .attr("height", h)
             .attr("fill", "none")
             .attr("stroke", "#ef4444")
             .attr("stroke-width", 2)
             .style("stroke-dasharray", "4,2");
        }
      });

    const zoom = d3.zoom<SVGSVGElement, unknown>()
      .scaleExtent([0.1, 15])
      .on("zoom", (event) => mainGroup.attr("transform", event.transform));
    svg.call(zoom);

    if (svgRef.current?.parentElement) {
        const { clientWidth: pw, clientHeight: ph } = svgRef.current.parentElement;
        const scale = Math.min(pw / width, ph / height) * 0.9;
        svg.call(zoom.transform, d3.zoomIdentity.translate((pw - width * scale) / 2, (ph - height * scale) / 2).scale(scale));
    }
  }, [layout, violations]);

  return (
    <div className="w-full h-full bg-slate-950 rounded-lg overflow-hidden border border-slate-800 shadow-inner relative">
       <svg ref={svgRef} className="block cursor-grab active:cursor-grabbing w-full h-full" />
    </div>
  );
});

export default MapRenderer;

