      zoomGroup.attr("transform", null); 
      svgNode.setAttribute("width", layout.width.toString());
      svgNode.setAttribute("height", layout.height.toString());
      svgNode.setAttribute("viewBox", `0 0 ${layout.width} ${layout.height}`);

      const serializer = new XMLSerializer();
      let svgString = serializer.serializeToString(svgNode);
      if (!svgString.match(/^<svg[^>]+xmlns="http\:\/\/www\.w3\.org\/2000\/svg"/)) {
        svgString = svgString.replace(/^<svg/, '<svg xmlns="http://www.w3.org/2000/svg"');
      }

      if (prevTransform) zoomGroup.attr("transform", prevTransform);

      const img = new Image();
      img.onload = () => {
        const canvas = document.createElement("canvas");
        canvas.width = layout.width;
        canvas.height = layout.height;
        const ctx = canvas.getContext("2d");
        if (ctx) {
          ctx.imageSmoothingEnabled = false; 
          ctx.fillStyle = "#0f172a"; 
          ctx.fillRect(0, 0, canvas.width, canvas.height);
          ctx.drawImage(img, 0, 0);
          const jpgUrl = canvas.toDataURL("image/jpeg", 0.98);
          const link = document.createElement("a");
          link.download = `architectural_plan_${Date.now()}.jpg`;
          link.href = jpgUrl;
          document.body.appendChild(link);
          link.click();
          document.body.removeChild(link);
        }
      };
      img.src = "data:image/svg+xml;base64," + btoa(unescape(encodeURIComponent(svgString)));
    }
  }));

  useEffect(() => {
    if (!layout || !svgRef.current) return;
    const svg = d3.select(svgRef.current);
    svg.selectAll("*").remove(); 

    const { width, height, elements } = layout;
    svg.attr("viewBox", `0 0 ${width} ${height}`)
       .attr("width", "100%")
       .attr("height", "100%")
       .style("shape-rendering", "geometricPrecision"); 

    // Add Pattern for hatching (Shear Walls)
    const defs = svg.append("defs");
    defs.append("pattern")
        .attr("id", "hatch")
        .attr("patternUnits", "userSpaceOnUse")
        .attr("width", 4)
        .attr("height", 4)
        .append("path")
        .attr("d", "M-1,1 l2,-2 M0,4 l4,-4 M3,5 l2,-2")
        .attr("stroke", "#4b5563")
        .attr("stroke-width", 0.5);

    const mainGroup = svg.append("g").attr("class", "main-group");

    // Z-Order: Higher index = rendered on top
    const zOrder = [
        ElementType.SLAB,
        ElementType.LIVING_ZONE,
        ElementType.BEDROOM_ZONE,
        ElementType.KITCHEN_ZONE,
        ElementType.BATHROOM_ZONE,
        ElementType.STORAGE_ZONE,
        ElementType.CORRIDOR,
        ElementType.LOBBY,
        ElementType.AISLE,
        ElementType.ELEVATOR_HALL,
        ElementType.SERVICE_SHAFT,
        ElementType.STAIRCASE,
        ElementType.ELEVATOR_SHAFT,
        // Structure layers on top of zones to show volume cuts
        ElementType.WALL_INTERNAL,
        ElementType.WALL_EXTERNAL,
        ElementType.SHEAR_WALL,
        ElementType.PILLAR,
        ElementType.WINDOW,
        ElementType.DOOR,
        ElementType.FIRE_DOOR,
        ElementType.FIRE_HYDRANT,
        ElementType.SAFE_EXIT_SIGN,
        ElementType.ELECTRICAL_BOX
    ];

    const sortedElements = [...elements].sort((a, b) => {
      const idxA = zOrder.indexOf(a.type as ElementType);
      const idxB = zOrder.indexOf(b.type as ElementType);
      return (idxA === -1 ? 999 : idxA) - (idxB === -1 ? 999 : idxB);
    });

    mainGroup.selectAll("g.element")
      .data(sortedElements)
      .enter()
      .append("g")
      .attr("class", "element")
      .attr("transform", d => {
          const rotation = d.rotation || 0;
          return `translate(${d.x}, ${d.y}) rotate(${rotation}, ${d.width/2}, ${d.height/2})`;
      })
      .each(function(this: any, d) {
        const g = d3.select(this);
        const style = ELEMENT_STYLES[d.type as string] || { fill: '#ff00ff', opacity: 0.5 };
        const w = d.width;
        const h = d.height;
        const cx = w / 2;
        const cy = h / 2;

        const isWall = [ElementType.WALL_EXTERNAL, ElementType.WALL_INTERNAL, ElementType.SHEAR_WALL].includes(d.type as ElementType);

        if (isWall) {
            // Render Wall as a volumetric section (Poché)
            g.append("rect")
             .attr("width", w)
             .attr("height", h)
             .attr("fill", style.fill)
             .attr("stroke", style.stroke || 'none')
             .attr("stroke-width", style.strokeWidth || 0);

            // Add extra hatch for Shear Walls to emphasize "Reinforced Concrete" volume
            if (d.type === ElementType.SHEAR_WALL) {
                g.append("rect")
                 .attr("width", w)
                 .attr("height", h)
                 .attr("fill", "url(#hatch)")
                 .attr("opacity", 0.3);
            }
        }
        else if (d.type === ElementType.WINDOW) {
            // Windows nested within walls
            g.append("rect")
             .attr("width", w)
             .attr("height", h)
             .attr("fill", style.fill)
             .attr("stroke", style.stroke || 'none')
             .attr("stroke-width", style.strokeWidth || 0);

            const isHorizontal = w > h;
            // Frame lines
            g.append("line")
             .attr("x1", isHorizontal ? 0 : cx).attr("y1", isHorizontal ? cy : 0)
             .attr("x2", isHorizontal ? w : cx).attr("y2", isHorizontal ? h : cy)
             .attr("stroke", "#0ea5e9").attr("stroke-width", 1);
        } 
        else if (d.type === ElementType.STAIRCASE) {
            g.append("rect")
             .attr("width", w)
             .attr("height", h)
             .attr("fill", style.fill)
             .attr("stroke", style.stroke || 'none')
             .attr("stroke-width", style.strokeWidth || 0);

            const isHorizontal = w > h;
            const stepSize = 6;
            const stepCount = Math.floor((isHorizontal ? w : h) / stepSize);

            for(let i=1; i<stepCount; i++) {
                g.append("line")
                 .attr("x1", isHorizontal ? i * stepSize : 0).attr("y1", isHorizontal ? 0 : i * stepSize)
                 .attr("x2", isHorizontal ? i * stepSize : w).attr("y2", isHorizontal ? h : i * stepSize)
                 .attr("stroke", "#374151").attr("stroke-width", 0.5);
            }
        }
        else if (d.type === ElementType.DOOR || d.type === ElementType.FIRE_DOOR) {
            const isFire = d.type === ElementType.FIRE_DOOR;
            const arcRadius = Math.max(w, h);

            // Door leaf (the solid part)
            g.append("rect")
             .attr("width", 2)
             .attr("height", arcRadius)
             .attr("fill", isFire ? '#ef4444' : '#f1f5f9')
             .attr("transform", `rotate(-90)`); // Show open

            // Swing arc
            g.append("path")
             .attr("d", `M 0 0 A ${arcRadius} ${arcRadius} 0 0 1 ${arcRadius} ${arcRadius}`)
             .attr("fill", "none")
             .attr("stroke", isFire ? '#ef4444' : '#94a3b8')
             .attr("stroke-dasharray", "2,2")
             .attr("stroke-width", 1);
        }
        else if (d.type === ElementType.PILLAR) {
            g.append("rect")
             .attr("width", w).attr("height", h)
             .attr("fill", style.fill)
             .attr("stroke", style.stroke || 'none')
             .attr("stroke-width", style.strokeWidth || 0);

            // Pillar internal cross
            g.append("line").attr("x1", 0).attr("y1", 0).attr("x2", w).attr("y2", h).attr("stroke", "#cbd5e1").attr("stroke-width", 0.5);
            g.append("line").attr("x1", w).attr("y1", 0).attr("x2", 0).attr("y2", h).attr("stroke", "#cbd5e1").attr("stroke-width", 0.5);
        }
        else {
            // Default Area/Zone rendering
            g.append("rect")
              .attr("width", w).attr("height", h)
              .attr("fill", style.fill)
              .attr("opacity", style.opacity)
              .attr("stroke", style.stroke || 'none')
              .attr("stroke-width", style.strokeWidth || 0);

            if (d.label || d.type.includes('zone')) {
                const labelText = d.label || (d.type as string).split('_').shift()?.toUpperCase();
                if (w > 40 && h > 30) {
                    g.append("text")
                     .attr("x", cx)
                     .attr("y", cy)
                     .attr("text-anchor", "middle")
                     .attr("dominant-baseline", "middle")
                     .attr("fill", "#64748b")
                     .attr("font-size", "10px")
                     .attr("font-family", "monospace")
                     .attr("font-weight", "600")
                     .attr("pointer-events", "none")
                     .text(labelText || '');
                }
            }
        }

        // Highlight violations
        if (violations.some(v => v.elementId === d.id)) {
            g.append("rect")
             .attr("width", w)
             .attr("height", h)
             .attr("fill", "none")
             .attr("stroke", "#ef4444")
             .attr("stroke-width", 2)
             .style("stroke-dasharray", "4,2");
        }
      });

    const zoom = d3.zoom<SVGSVGElement, unknown>()
      .scaleExtent([0.1, 15])
      .on("zoom", (event) => mainGroup.attr("transform", event.transform));
    svg.call(zoom);

    if (svgRef.current?.parentElement) {
        const { clientWidth: pw, clientHeight: ph } = svgRef.current.parentElement;
        const scale = Math.min(pw / width, ph / height) * 0.9;
        svg.call(zoom.transform, d3.zoomIdentity.translate((pw - width * scale) / 2, (ph - height * scale) / 2).scale(scale));
    }
  }, [layout, violations]);

  return (
    <div className="w-full h-full bg-slate-950 rounded-lg overflow-hidden border border-slate-800 shadow-inner relative">
       <svg ref={svgRef} className="block cursor-grab active:cursor-grabbing w-full h-full" />
    </div>
  );
});

export default MapRenderer;

import { create } from 'zustand';
import { ParkingLayout, ConstraintViolation } from './types';

interface AppState {
  layout: ParkingLayout | null;
  violations: ConstraintViolation[];
  isGenerating: boolean;
  error: string | null;
  logs: string[];
  generationTime: number | null;
  showLabels: boolean;

  // Actions
  setLayout: (layout: ParkingLayout | null) => void;
  setViolations: (violations: ConstraintViolation[]) => void;
  setIsGenerating: (isGenerating: boolean) => void;
  setError: (error: string | null) => void;
  addLog: (msg: string) => void;
  clearLogs: () => void;
  setGenerationTime: (time: number | null) => void;
  toggleLabels: () => void;
}

export const useStore = create<AppState>((set) => ({
  layout: null,
  violations: [],
  isGenerating: false,
  error: null,
  logs: [],
  generationTime: null,
  showLabels: true,

  setLayout: (layout) => set({ layout }),
  setViolations: (violations) => set({ violations }),
  setIsGenerating: (isGenerating) => set({ isGenerating }),
  setError: (error) => set({ error }),
  addLog: (msg) => set((state) => ({ logs: [...state.logs, msg] })),
  clearLogs: () => set({ logs: [] }),
  setGenerationTime: (time) => set({ generationTime: time }),
  toggleLabels: () => set((state) => ({ showLabels: !state.showLabels })),
}));

import React, { useEffect, useRef, forwardRef, useImperativeHandle } from 'react';
import * as d3 from 'd3';
import { ElementType, LayoutElement } from '../types';
import { useStore } from '../store';

const ELEMENT_STYLES: Record<string, { fill: string; opacity: number; stroke?: string; strokeWidth?: number }> = {
  // Structure: Volumetric & Solid
  [ElementType.SLAB]: { fill: '#020617', opacity: 1 },
  [ElementType.WALL_EXTERNAL]: { fill: '#1e293b', opacity: 1, stroke: '#0f172a', strokeWidth: 1 },
  [ElementType.WALL_INTERNAL]: { fill: '#475569', opacity: 1, stroke: '#334155', strokeWidth: 1 },
  [ElementType.SHEAR_WALL]: { fill: '#0f172a', opacity: 1, stroke: '#000000', strokeWidth: 1.5 },
  [ElementType.PILLAR]: { fill: '#1e293b', opacity: 1, stroke: '#000000', strokeWidth: 1 },

  // Circulation: Clear solid zones
  [ElementType.CORRIDOR]: { fill: '#1e293b', opacity: 0.4 },
  [ElementType.LOBBY]: { fill: '#1e293b', opacity: 0.6 },
  [ElementType.AISLE]: { fill: '#1e293b', opacity: 0.3 },

  // Core: Distinct high-contrast colors
  [ElementType.ELEVATOR_SHAFT]: { fill: '#7f1d1d', opacity: 1, stroke: '#450a0a', strokeWidth: 1 },
  [ElementType.STAIRCASE]: { fill: '#92400e', opacity: 1, stroke: '#451a03', strokeWidth: 1 },
  [ElementType.SERVICE_SHAFT]: { fill: '#064e3b', opacity: 1, stroke: '#022c22', strokeWidth: 1 },
  [ElementType.ELEVATOR_HALL]: { fill: '#1e293b', opacity: 0.7 },

  // Zones: Low-opacity functionality blocks
  [ElementType.LIVING_ZONE]: { fill: '#1d4ed8', opacity: 0.15, stroke: '#1d4ed8', strokeWidth: 0.5 },
  [ElementType.BEDROOM_ZONE]: { fill: '#6d28d9', opacity: 0.15, stroke: '#6d28d9', strokeWidth: 0.5 },
  [ElementType.KITCHEN_ZONE]: { fill: '#b45309', opacity: 0.15, stroke: '#b45309', strokeWidth: 0.5 },
  [ElementType.BATHROOM_ZONE]: { fill: '#047857', opacity: 0.15, stroke: '#047857', strokeWidth: 0.5 },
  [ElementType.STORAGE_ZONE]: { fill: '#374151', opacity: 0.15, stroke: '#374151', strokeWidth: 0.5 },

  // Openings
  [ElementType.DOOR]: { fill: '#f8fafc', opacity: 1 },
  [ElementType.FIRE_DOOR]: { fill: '#ef4444', opacity: 1 },
  [ElementType.WINDOW]: { fill: '#7dd3fc', opacity: 0.8, stroke: '#0ea5e9', strokeWidth: 2 },

  // MEP & Safety
  [ElementType.FIRE_HYDRANT]: { fill: '#ef4444', opacity: 1 },
  [ElementType.SAFE_EXIT_SIGN]: { fill: '#22c55e', opacity: 1 },
  [ElementType.HVAC_VENT]: { fill: '#94a3b8', opacity: 0.5 },
  [ElementType.ELECTRICAL_BOX]: { fill: '#eab308', opacity: 1 }
};

export interface MapRendererHandle {
  downloadJpg: () => void;
}

const MapRenderer = forwardRef<MapRendererHandle>((props, ref) => {
  const svgRef = useRef<SVGSVGElement>(null);
  const { layout, violations, showLabels } = useStore();

  useImperativeHandle(ref, () => ({
    downloadJpg: () => {
      if (!svgRef.current || !layout) return;
      const svgNode = svgRef.current;
      const zoomGroup = d3.select(svgNode).select("g.main-group");
      const prevTransform = zoomGroup.attr("transform");
      zoomGroup.attr("transform", null); 
      svgNode.setAttribute("width", layout.width.toString());
      svgNode.setAttribute("height", layout.height.toString());
      svgNode.setAttribute("viewBox", `0 0 ${layout.width} ${layout.height}`);

      const serializer = new XMLSerializer();
      let svgString = serializer.serializeToString(svgNode);
      if (!svgString.match(/^<svg[^>]+xmlns="http\:\/\/www\.w3\.org\/2000\/svg"/)) {
        svgString = svgString.replace(/^<svg/, '<svg xmlns="http://www.w3.org/2000/svg"');
      }

      if (prevTransform) zoomGroup.attr("transform", prevTransform);

      const img = new Image();
      img.onload = () => {
        const canvas = document.createElement("canvas");
        canvas.width = layout.width;
        canvas.height = layout.height;
        const ctx = canvas.getContext("2d");
        if (ctx) {
          ctx.fillStyle = "#020617"; 
          ctx.fillRect(0, 0, canvas.width, canvas.height);
          ctx.drawImage(img, 0, 0);
          const jpgUrl = canvas.toDataURL("image/jpeg", 0.95);
          const link = document.createElement("a");
          link.download = `floor_plan_design.jpg`;
          link.href = jpgUrl;
          document.body.appendChild(link);
          link.click();
          document.body.removeChild(link);
        }
      };
      img.src = "data:image/svg+xml;base64," + btoa(unescape(encodeURIComponent(svgString)));
    }
  }));

  useEffect(() => {
    if (!layout || !svgRef.current) return;
    const svg = d3.select(svgRef.current);
    svg.selectAll("*").remove(); 

    const { width, height, elements } = layout;
    svg.attr("viewBox", `0 0 ${width} ${height}`)
       .attr("width", "100%")
       .attr("height", "100%")
       .style("shape-rendering", "geometricPrecision"); 

    const mainGroup = svg.append("g").attr("class", "main-group");

    const zOrder = [
        ElementType.SLAB,
        ElementType.LIVING_ZONE, ElementType.BEDROOM_ZONE, ElementType.KITCHEN_ZONE, ElementType.BATHROOM_ZONE, ElementType.STORAGE_ZONE,
        ElementType.CORRIDOR, ElementType.LOBBY, ElementType.AISLE, ElementType.ELEVATOR_HALL,
        ElementType.SERVICE_SHAFT, ElementType.STAIRCASE, ElementType.ELEVATOR_SHAFT,
        ElementType.WALL_INTERNAL, ElementType.WALL_EXTERNAL, ElementType.SHEAR_WALL, ElementType.PILLAR,
        ElementType.WINDOW, ElementType.DOOR, ElementType.FIRE_DOOR
    ];

    const sortedElements = [...elements].sort((a, b) => {
      const idxA = zOrder.indexOf(a.type as ElementType);
      const idxB = zOrder.indexOf(b.type as ElementType);
      return (idxA === -1 ? 999 : idxA) - (idxB === -1 ? 999 : idxB);
    });

    mainGroup.selectAll("g.element")
      .data(sortedElements)
      .enter()
      .append("g")
      .attr("class", "element")
      .attr("transform", d => {
          const rotation = d.rotation || 0;
          return `translate(${d.x}, ${d.y}) rotate(${rotation}, ${d.width/2}, ${d.height/2})`;
      })
      .each(function(this: any, d) {
        const g = d3.select(this);
        const style = ELEMENT_STYLES[d.type as string] || { fill: '#ff00ff', opacity: 0.5 };
        const w = d.width;
        const h = d.height;
        const cx = w / 2;
        const cy = h / 2;

        // Render solid volume
        g.append("rect")
          .attr("width", w).attr("height", h)
          .attr("fill", style.fill)
          .attr("opacity", style.opacity)
          .attr("stroke", style.stroke || 'none')
          .attr("stroke-width", style.strokeWidth || 0);

        // Functional Details (Arrows/Paths for specific elements)
        if (d.type === ElementType.STAIRCASE) {
            const isHorizontal = w > h;
            g.append("path")
             .attr("d", isHorizontal ? `M 10 ${cy} L ${w-10} ${cy} M ${w-20} ${cy-5} L ${w-10} ${cy} L ${w-20} ${cy+5}` : `M ${cx} 10 L ${cx} ${h-10} M ${cx-5} ${h-20} L ${cx} ${h-10} L ${cx+5} ${h-20}`)
             .attr("stroke", "#ffffff").attr("fill", "none").attr("stroke-width", 2).attr("opacity", 0.6);
        }

        if (d.type === ElementType.WINDOW) {
            const isHorizontal = w > h;
            g.append("line")
             .attr("x1", isHorizontal ? 0 : cx).attr("y1", isHorizontal ? cy : 0)
             .attr("x2", isHorizontal ? w : cx).attr("y2", isHorizontal ? h : cy)
             .attr("stroke", "#ffffff").attr("stroke-width", 1).attr("opacity", 0.5);
        }

        // Labels
        if (showLabels) {
            const labelText = d.label || (d.type as string).replace(/_zone|room/g, '').replace(/_/g, ' ').toUpperCase();
            const isStructural = [ElementType.WALL_EXTERNAL, ElementType.WALL_INTERNAL, ElementType.SHEAR_WALL, ElementType.DOOR, ElementType.WINDOW].includes(d.type as ElementType);

            if (!isStructural && w > 30 && h > 20) {
                g.append("text")
                 .attr("x", cx)
                 .attr("y", cy)
                 .attr("text-anchor", "middle")
                 .attr("dominant-baseline", "middle")
                 .attr("fill", "#94a3b8")
                 .attr("font-size", "8px")
                 .attr("font-family", "Inter, sans-serif")
                 .attr("font-weight", "600")
                 .attr("pointer-events", "none")
                 .text(labelText);
            }
        }

        if (violations.some(v => v.elementId === d.id)) {
            g.append("rect").attr("width", w).attr("height", h).attr("fill", "none").attr("stroke", "#ef4444").attr("stroke-width", 2).style("stroke-dasharray", "4,2");
        }
      });

    const zoom = d3.zoom<SVGSVGElement, unknown>()
      .scaleExtent([0.1, 15])
      .on("zoom", (event) => mainGroup.attr("transform", event.transform));
    svg.call(zoom);

    if (svgRef.current?.parentElement) {
        const { clientWidth: pw, clientHeight: ph } = svgRef.current.parentElement;
        const scale = Math.min(pw / width, ph / height) * 0.9;
        svg.call(zoom.transform, d3.zoomIdentity.translate((pw - width * scale) / 2, (ph - height * scale) / 2).scale(scale));
    }
  }, [layout, violations, showLabels]);

  return (
    <div className="w-full h-full bg-slate-950 rounded-lg overflow-hidden border border-slate-800 shadow-inner relative">
       <svg ref={svgRef} className="block cursor-grab active:cursor-grabbing w-full h-full" />
    </div>
  );
});

