import { GoogleGenAI } from "@google/genai";
import { jsonrepair } from "jsonrepair";
import { ParkingLayout, ElementType, ConstraintViolation, LayoutElement } from "../types";
import { validateLayout } from "../utils/geometry";
import { PROMPTS } from "../utils/prompts";

const MODEL_PRIMARY = "gemini-3-pro-preview";
const MODEL_FALLBACK = "gemini-3-flash-preview"; 

let cachedTier: 'HIGH' | 'LOW' | null = null;

const getApiKey = () => process.env.API_KEY;
const sleep = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

const mergeLayoutElements = (original: LayoutElement[], updates: LayoutElement[]): LayoutElement[] => {
  const elementMap = new Map(original.map(el => [el.id, el]));
  updates.forEach(update => {
    const id = update.id || `el_${Math.random().toString(36).substr(2, 9)}`;
    elementMap.set(id, { ...update, id });
  });
  return Array.from(elementMap.values());
};

const postProcessLayout = (layout: ParkingLayout): ParkingLayout => {
    return {
        ...layout,
        elements: layout.elements.map(el => ({
            ...el,
            x: Math.round(el.x),
            y: Math.round(el.y),
            width: Math.round(el.width),
            height: Math.round(el.height)
        }))
    };
};

async function determineModelTier(ai: GoogleGenAI): Promise<'HIGH' | 'LOW'> {
    if (cachedTier) return cachedTier;
    try {
        await ai.models.generateContent({ model: MODEL_PRIMARY, contents: "test", config: { maxOutputTokens: 1 } });
        cachedTier = 'HIGH';
    } catch (e: any) {
        cachedTier = 'LOW';
    }
    return cachedTier;
}

const normalizeType = (t: string | undefined): string => {
  if (!t) return ElementType.WALL_INTERNAL;
  const lower = t.toLowerCase().trim().replace(/\s+/g, '_');
  const map: Record<string, string> = {
    'exterior_wall': ElementType.WALL_EXTERNAL, 
    'partition_wall': ElementType.WALL_INTERNAL,
    'slab': ElementType.SLAB, 
    'pillar': ElementType.PILLAR,
    'elevator_shaft': ElementType.ELEVATOR_SHAFT, 
    'staircase': ElementType.STAIRCASE,
    'corridor': ElementType.CORRIDOR, 
    'living_room': ElementType.LIVING_ZONE,
    'bedroom': ElementType.BEDROOM_ZONE, 
    'kitchen': ElementType.KITCHEN_ZONE,
    'bathroom': ElementType.BATHROOM_ZONE, 
    'door': ElementType.DOOR, 
    'window': ElementType.WINDOW
  };
  return map[lower] || lower;
};

const cleanAndParseJSON = (text: string): any => {
  try {
    let cleanText = text.replace(/```json\s*|```/g, "").trim();
    const firstOpen = cleanText.indexOf('{');
    const lastClose = cleanText.lastIndexOf('}');
    if (firstOpen !== -1 && lastClose !== -1) cleanText = cleanText.substring(firstOpen, lastClose + 1);
    const repaired = jsonrepair(cleanText);
    return JSON.parse(repaired);
  } catch (e) {
    throw new Error(`AI parse error: ${(e as Error).message}`);
  }
};

const mapToInternalLayout = (rawData: any): ParkingLayout => ({
    width: Number(rawData.width || 800),
    height: Number(rawData.height || 600),
    elements: (rawData.elements || []).map((e: any) => ({
        id: String(e.id || `el_${Math.random().toString(36).substr(2, 9)}`),
        type: normalizeType(e.t || e.type),
        x: Number(e.x || 0),
        y: Number(e.y || 0),
        width: Number(e.w ?? e.width ?? 10),
        height: Number(e.h ?? e.height ?? 10),
        rotation: Number(e.r || 0),
        label: e.l
    }))
});

const generateWithRetry = async (ai: GoogleGenAI, params: any, retries = 3) => {
    for (let i = 0; i < retries; i++) {
        try {
            return await ai.models.generateContent(params);
        } catch (e: any) {
            if (e.message?.includes("429") && i < retries - 1) {
              await sleep(3000 * Math.pow(2, i));
              continue;
            }
            if (i === retries - 1) throw e;
        }
    }
    throw new Error("Failed after retries");
};

const runIterativeFix = async (layout: ParkingLayout, ai: GoogleGenAI, model: string, onLog?: (m: string) => void, maxPasses = 3): Promise<ParkingLayout> => {
    let currentLayout = layout;
    for (let pass = 1; pass <= maxPasses; pass++) {
        const violations = validateLayout(currentLayout);
        if (violations.length === 0) break;

        onLog?.(`🔧 Optimization pass ${pass}...`);
        const simplified = {
            width: currentLayout.width,
            height: currentLayout.height,
            elements: currentLayout.elements.map(e => ({ id: e.id, t: e.type, x: Math.round(e.x), y: Math.round(e.y), w: Math.round(e.width), h: Math.round(e.height) }))
        };

        try {
            const response = await generateWithRetry(ai, { 
                model, 
                contents: PROMPTS.fix(simplified as any, violations), 
                config: { responseMimeType: "application/json", temperature: 0.1 } 
            }, 1);
            const rawData = cleanAndParseJSON(response.text || "{}");
            const fixedLayout = mapToInternalLayout(rawData);
            currentLayout = { ...currentLayout, elements: mergeLayoutElements(currentLayout.elements, fixedLayout.elements) };
        } catch (e: any) { break; }
    }
    return currentLayout;
};

export const generateParkingLayout = async (description: string, onLog?: (msg: string) => void): Promise<ParkingLayout> => {
  const apiKey = getApiKey();
  if (!apiKey) throw new Error("Missing API Key.");
  const ai = new GoogleGenAI({ apiKey });
  let tier = await determineModelTier(ai);
  let currentModel = tier === 'HIGH' ? MODEL_PRIMARY : MODEL_FALLBACK;

  try {
    onLog?.("🏗️ Phase 1: Generating Building Structure...");
    const response = await generateWithRetry(ai, { 
      model: currentModel, 
      contents: PROMPTS.generation(description), 
      config: { responseMimeType: "application/json" } 
    }, 2);
    const rawData = cleanAndParseJSON(response.text);
    if (rawData.reasoning_plan && onLog) onLog(`🧠 Architecture: ${rawData.reasoning_plan}`);
    let layout = mapToInternalLayout(rawData);
    layout = await runIterativeFix(layout, ai, currentModel, onLog);
    return postProcessLayout(layout);
  } catch (error: any) { throw error; }
};

export const refineFloorPlan = async (currentLayout: ParkingLayout, onLog?: (msg: string) => void): Promise<ParkingLayout> => {
  const apiKey = getApiKey();
  if (!apiKey) throw new Error("Missing API Key");
  const ai = new GoogleGenAI({ apiKey });
  let tier = await determineModelTier(ai);
  let currentModel = tier === 'HIGH' ? MODEL_PRIMARY : MODEL_FALLBACK;

  try {
    onLog?.("🛋️ Phase 2: Populating interior furniture...");
    const simplified = currentLayout.elements.map(e => ({ id: e.id, t: e.type, x: e.x, y: e.y, w: e.width, h: e.height }));
    const response = await generateWithRetry(ai, { 
        model: currentModel, 
        contents: PROMPTS.refinement({ elements: simplified }, currentLayout.width, currentLayout.height), 
        config: { responseMimeType: "application/json" } 
    }, 2);

    const rawData = cleanAndParseJSON(response.text);
    const newElements = mapToInternalLayout(rawData).elements;

    if (newElements.length > 0) {
        onLog?.(`✨ Furnished: ${newElements.map(e => e.label || e.type).join(', ')}`);
    }

    let layout: ParkingLayout = { ...currentLayout, elements: mergeLayoutElements(currentLayout.elements, newElements) };
    layout = await runIterativeFix(layout, ai, currentModel, onLog);
    return postProcessLayout(layout);
  } catch (error: any) { throw error; }
};

export const augmentLayoutWithRoads = refineFloorPlan;

import React, { useEffect, useRef, forwardRef, useImperativeHandle } from 'react';
import * as d3 from 'd3';
import { ElementType, LayoutElement } from '../types';
import { useStore } from '../store';

// STANDARDIZED ARCHITECTURAL PALETTE - NO STROKES
export const ELEMENT_STYLES: Record<string, { fill: string; opacity: number }> = {
  // --- 1. Structure (High Density) ---
  [ElementType.SLAB]: { fill: '#020617', opacity: 1 },
  [ElementType.WALL_EXTERNAL]: { fill: '#0f172a', opacity: 1 },
  [ElementType.WALL_INTERNAL]: { fill: '#334155', opacity: 1 },
  [ElementType.SHEAR_WALL]: { fill: '#000000', opacity: 1 },
  [ElementType.PILLAR]: { fill: '#1e293b', opacity: 1 },

  // --- 2. Vertical Cores (Vibrant) ---
  [ElementType.ELEVATOR_SHAFT]: { fill: '#991b1b', opacity: 1 },
  [ElementType.STAIRCASE]: { fill: '#b45309', opacity: 1 },
  [ElementType.SERVICE_SHAFT]: { fill: '#064e3b', opacity: 1 },

  // --- 3. Zones (Translucent Underlay) ---
  [ElementType.LIVING_ZONE]: { fill: '#0ea5e9', opacity: 0.15 },
  [ElementType.BEDROOM_ZONE]: { fill: '#8b5cf6', opacity: 0.15 },
  [ElementType.KITCHEN_ZONE]: { fill: '#eab308', opacity: 0.15 },
  [ElementType.BATHROOM_ZONE]: { fill: '#14b8a6', opacity: 0.15 },
  [ElementType.CORRIDOR]: { fill: '#1e293b', opacity: 0.15 },
  [ElementType.STORAGE_ZONE]: { fill: '#64748b', opacity: 0.15 },

  // --- 4. Furniture & Fixtures (Refinement Step - Solid Blocks) ---
  'bed': { fill: '#4338ca', opacity: 1 },
  'sofa': { fill: '#be123c', opacity: 1 },
  'dining_table': { fill: '#78350f', opacity: 1 },
  'desk': { fill: '#0e7490', opacity: 1 },
  'wardrobe': { fill: '#6d28d9', opacity: 1 },
  'toilet': { fill: '#f8fafc', opacity: 1 },
  'sink': { fill: '#1d4ed8', opacity: 1 },
  'cabinet': { fill: '#475569', opacity: 1 },

  // --- 5. Openings ---
  [ElementType.DOOR]: { fill: '#f8fafc', opacity: 1 },
  [ElementType.WINDOW]: { fill: '#7dd3fc', opacity: 0.8 },
};

export interface MapRendererHandle {
  downloadJpg: () => void;
}

const MapRenderer = forwardRef<MapRendererHandle>((props, ref) => {
  const svgRef = useRef<SVGSVGElement>(null);
  const { layout, violations, showLabels } = useStore();

  useImperativeHandle(ref, () => ({
    downloadJpg: () => {
      if (!svgRef.current || !layout) return;
      const svgNode = svgRef.current;
      const zoomGroup = d3.select(svgNode).select("g.main-group");
      const prevTransform = zoomGroup.attr("transform");
      zoomGroup.attr("transform", null); 
      svgNode.setAttribute("width", layout.width.toString());
      svgNode.setAttribute("height", layout.height.toString());
      svgNode.setAttribute("viewBox", `0 0 ${layout.width} ${layout.height}`);

      const serializer = new XMLSerializer();
      let svgString = serializer.serializeToString(svgNode);
      if (!svgString.match(/^<svg[^>]+xmlns="http\:\/\/www\.w3\.org\/2000\/svg"/)) {
        svgString = svgString.replace(/^<svg/, '<svg xmlns="http://www.w3.org/2000/svg"');
      }

      if (prevTransform) zoomGroup.attr("transform", prevTransform);

      const img = new Image();
      img.onload = () => {
        const canvas = document.createElement("canvas");
        canvas.width = layout.width;
        canvas.height = layout.height;
        const ctx = canvas.getContext("2d");
        if (ctx) {
          ctx.fillStyle = "#020617"; 
          ctx.fillRect(0, 0, canvas.width, canvas.height);
          ctx.drawImage(img, 0, 0);
          const jpgUrl = canvas.toDataURL("image/jpeg", 0.95);
          const link = document.createElement("a");
          link.download = `blueprint_${Date.now()}.jpg`;
          link.href = jpgUrl;
          document.body.appendChild(link);
          link.click();
          document.body.removeChild(link);
        }
      };
      img.src = "data:image/svg+xml;base64," + btoa(unescape(encodeURIComponent(svgString)));
    }
  }));

  useEffect(() => {
    if (!layout || !svgRef.current) return;
    const svg = d3.select(svgRef.current);
    svg.selectAll("*").remove(); 

    const { width, height, elements } = layout;
    svg.attr("viewBox", `0 0 ${width} ${height}`)
       .attr("width", "100%")
       .attr("height", "100%")
       .style("shape-rendering", "geometricPrecision"); 

    const mainGroup = svg.append("g").attr("class", "main-group");

    // Z-Order: Higher index renders on top
    const zOrder = [
        ElementType.SLAB,
        ElementType.LIVING_ZONE, ElementType.BEDROOM_ZONE, ElementType.KITCHEN_ZONE, ElementType.BATHROOM_ZONE, ElementType.STORAGE_ZONE,
        ElementType.CORRIDOR, 
        'cabinet', 'wardrobe', 'desk', 'dining_table', 'sofa', 'bed', 'toilet', 'sink',
        ElementType.SERVICE_SHAFT, ElementType.STAIRCASE, ElementType.ELEVATOR_SHAFT,
        ElementType.WALL_INTERNAL, ElementType.WALL_EXTERNAL, ElementType.SHEAR_WALL, ElementType.PILLAR,
        ElementType.WINDOW, ElementType.DOOR
    ];

    const sortedElements = [...elements].sort((a, b) => {
      const idxA = zOrder.indexOf(a.type as string);
      const idxB = zOrder.indexOf(b.type as string);
      return (idxA === -1 ? 500 : idxA) - (idxB === -1 ? 500 : idxB);
    });

    mainGroup.selectAll("g.element")
      .data(sortedElements)
      .enter()
      .append("g")
      .attr("class", "element")
      .attr("transform", d => `translate(${d.x}, ${d.y}) rotate(${d.rotation || 0}, ${d.width/2}, ${d.height/2})`)
      .each(function(this: any, d) {
        const g = d3.select(this);
        const style = ELEMENT_STYLES[d.type as string] || { fill: '#475569', opacity: 0.5 };
        const w = d.width;
        const h = d.height;
        const cx = w / 2;
        const cy = h / 2;

        // Render solid geometry - Removed rx and strokes
        g.append("rect")
          .attr("width", w).attr("height", h)
          .attr("fill", style.fill)
          .attr("opacity", style.opacity)
          .attr("stroke", "none");

        // Functional Decorations (Minimalist, no border strokes)
        if (d.type === ElementType.STAIRCASE) {
            g.append("path")
             .attr("d", w > h ? `M 10 ${cy} L ${w-10} ${cy} M ${w-20} ${cy-5} L ${w-10} ${cy} L ${w-20} ${cy+5}` : `M ${cx} 10 L ${cx} ${h-10} M ${cx-5} ${h-20} L ${cx} ${h-10} L ${cx+5} ${h-20}`)
             .attr("stroke", "#ffffff").attr("fill", "none").attr("stroke-width", 1.5).attr("opacity", 0.4);
        }

        // Semantic Annotations
        if (showLabels) {
            const labelText = d.label || (d.type as string).toUpperCase().replace(/_/g, ' ');
            const isStructural = [ElementType.WALL_EXTERNAL, ElementType.WALL_INTERNAL, ElementType.SHEAR_WALL, ElementType.PILLAR].includes(d.type as ElementType);

            if (!isStructural && w > 20 && h > 12) {
                g.append("text")
                 .attr("x", cx)
                 .attr("y", cy)
                 .attr("text-anchor", "middle")
                 .attr("dominant-baseline", "middle")
                 .attr("fill", "#ffffff")
                 .attr("font-size", "6px")
                 .attr("font-family", "Inter, sans-serif")
                 .attr("font-weight", "700")
                 .attr("opacity", 0.8)
                 .attr("pointer-events", "none")
                 .text(labelText);
            }
        }

        if (violations.some(v => v.elementId === d.id)) {
            g.append("rect").attr("width", w).attr("height", h).attr("fill", "none").attr("stroke", "#ef4444").attr("stroke-width", 2).style("stroke-dasharray", "4,2");
        }
      });

    const zoom = d3.zoom<SVGSVGElement, unknown>()
      .scaleExtent([0.1, 15])
      .on("zoom", (event) => mainGroup.attr("transform", event.transform));
    svg.call(zoom);

    if (svgRef.current?.parentElement) {
        const { clientWidth: pw, clientHeight: ph } = svgRef.current.parentElement;
        const scale = Math.min(pw / width, ph / height) * 0.9;
        svg.call(zoom.transform, d3.zoomIdentity.translate((pw - width * scale) / 2, (ph - height * scale) / 2).scale(scale));
    }
  }, [layout, violations, showLabels]);

  return (
    <div className="w-full h-full bg-slate-950 rounded-lg overflow-hidden border border-slate-800 shadow-inner relative">
       <svg ref={svgRef} className="block cursor-grab active:cursor-grabbing w-full h-full" />
    </div>
  );
});

export default MapRenderer;

