               <div className="flex items-center gap-1"><span className="w-2 h-2 rounded-full bg-blue-500"></span> Pro</div>
               <div className="flex items-center gap-1"><span className="w-2 h-2 rounded-full bg-amber-500"></span> Flash</div>
